const invincibleQuestions = [
  {t:"m",q:"¿Cuál es el verdadero nombre de Invincible?",o:["Mark Grayson","Nolan Grayson","Ryan Grayson","Lucas Grayson"],a:0,exp:"Mark Grayson es el nombre civil de Invincible, hijo de Omni-Man.",extra:"Mark tiene 17 años cuando comienza su historia como superhéroe."},
  {t:"m",q:"¿Qué colores tiene el traje clásico de Invincible?",o:["Rojo y negro","Azul y dorado","Verde y amarillo","Azul y blanco"],a:1,exp:"El traje icónico de Invincible es azul con detalles dorados.",extra:"El diseño del traje fue creado junto a Ryan Ottley en el cómic original."},
  {t:"m",q:"¿Cuántos años tenía Mark Grayson cuando desarrolló sus poderes?",o:["14 años","16 años","17 años","18 años"],a:2,exp:"Mark tenía 17 años cuando finalmente manifestó sus poderes Viltrumitas.",extra:"Su padre Nolan esperaba que los poderes aparecieran mucho antes."},
  {t:"m",q:"¿Cuál es el verdadero nombre de Omni-Man?",o:["Thragg Grayson","Nolan Grayson","Volan Grayson","Krel Grayson"],a:1,exp:"Nolan Grayson es el nombre que Omni-Man adoptó en la Tierra.",extra:"Omni-Man es miembro del Imperio Viltrumita enviado como espía a la Tierra."},
  {t:"m",q:"¿Para qué organización es en realidad un agente Omni-Man?",o:["La Coalición de Planetas","Los Guardianes del Globo","El Imperio Viltrumita","La GDA"],a:2,exp:"Omni-Man es un agente del Imperio Viltrumita, enviado para preparar la conquista de la Tierra.",extra:"Los Viltrumitas son una raza conquistadora que domina planetas enteros."},
  {t:"m",q:"¿En qué número de cómic ocurre la brutal revelación de Omni-Man?",o:["Issue #5","Issue #8","Issue #11","Issue #15"],a:2,exp:"El issue #11 de Invincible muestra la verdad sobre Omni-Man y la pelea con su hijo.",extra:"Este número es considerado uno de los momentos más impactantes de la historia del cómic."},
  {t:"m",q:"¿En qué episodio de la temporada 1 de Amazon Prime ocurre la pelea entre Invincible y Omni-Man?",o:["Episodio 5","Episodio 6","Episodio 7","Episodio 8"],a:3,exp:"El episodio 1x08 'Where I Really Come From' muestra la devastadora pelea padre-hijo.",extra:"El episodio fue tan violento que generó una gran reacción en las redes sociales."},
  {t:"m",q:"¿Cuál es la debilidad conocida de los Viltrumitas?",o:["La kryptonita espacial","Una frecuencia sonora específica","El agua salada","La luz ultravioleta"],a:1,exp:"Los Viltrumitas son vulnerables a una frecuencia sonora muy específica que destruye sus oídos internos.",extra:"Esta debilidad fue descubierta y explotada durante la Guerra Viltrumita."},
  {t:"m",q:"¿Cómo se llama la madre de Mark Grayson?",o:["Sandra Grayson","Debbie Grayson","Diana Grayson","Carol Grayson"],a:1,exp:"Debbie Grayson es la madre de Mark y esposa de Nolan, quien debe lidiar con la traición de su marido.",extra:"Debbie es humana y su vida cambia drásticamente al descubrir la verdad sobre Nolan."},
  {t:"m",q:"¿Cuál es el verdadero nombre de Atom Eve?",o:["Eve Summers","Samantha Eve Wilkins","Eve Parker","Samantha Stone"],a:1,exp:"Atom Eve se llama Samantha Eve Wilkins en su vida civil.",extra:"Atom Eve fue creada en un programa gubernamental secreto que manipuló su ADN."},
  {t:"m",q:"¿Cuál es el poder principal de Atom Eve?",o:["Vuelo supersónico","Manipulación de la materia","Telepatía","Control del tiempo"],a:1,exp:"Atom Eve puede manipular y reorganizar la materia a nivel molecular.",extra:"Su poder es considerado uno de los más versátiles y poderosos del universo de Invincible."},
  {t:"m",q:"¿Quién es el mejor amigo de Mark Grayson en el instituto?",o:["Rex Splode","William Clockwell","Todd Murphy","Amber Bennett"],a:1,exp:"William Clockwell es el mejor amigo de Mark desde la secundaria.",extra:"William eventualmente descubre la identidad de Mark como Invincible."},
  {t:"m",q:"¿Qué característica personal importante tiene William Clockwell?",o:["Es mutante","Es gay","Es hijo de un superhéroe","Tiene poderes latentes"],a:1,exp:"William Clockwell es gay, y esto forma parte de su arco de personaje en la historia.",extra:"Su amistad con Mark es uno de los lazos más sólidos de la serie."},
  {t:"m",q:"¿Quién dirige la Agencia de Defensa Global (GDA)?",o:["Cecil Stedman","Donald Ferguson","Rex Splode","Black Samson"],a:0,exp:"Cecil Stedman es el director pragmático y manipulador de la GDA.",extra:"Cecil usa a Mark para sus propios fines y no duda en tomar decisiones moralmente cuestionables."},
  {t:"m",q:"¿Cómo describe mejor la personalidad de Cecil Stedman?",o:["Honesto y transparente","Pragmático y despiadado","Cobarde y evasivo","Heroico e impulsivo"],a:1,exp:"Cecil Stedman es notoriamente pragmático y despiadado, dispuesto a cualquier cosa por proteger la Tierra.",extra:"Cecil tiene un parche en el ojo y numerosas cicatrices de batallas anteriores."},
  {t:"m",q:"¿Qué son los Reanimen creados por Cecil Stedman?",o:["Robots de combate","Zombies mecánicos formados por partes humanas","Clones genéticos","Androides sintéticos"],a:1,exp:"Los Reanimen son cadáveres humanos reanimados y combinados con tecnología cibernética avanzada.",extra:"Los Reanimen son uno de los proyectos más controvertidos de Cecil dentro de la GDA."},
  {t:"m",q:"¿Quiénes conforman originalmente el Teen Team?",o:["Mark, Eve y William","Rex Splode, Dupli-Kate y Robot","Mark, Rex y Eve","Robot, Eve y Black Samson"],a:1,exp:"El Teen Team original estaba formado por Rex Splode, Dupli-Kate y Robot.",extra:"Mark Grayson eventualmente se une al Teen Team tras revelar sus poderes."},
  {t:"m",q:"¿Cuál es el poder de Rex Splode?",o:["Vuelo y superfuerza","Poderes explosivos que activan objetos","Duplicación de su cuerpo","Control del fuego"],a:1,exp:"Rex Splode puede cargar objetos con energía explosiva y detonarlos a voluntad.",extra:"Rex también tiene fragmentos de metal en su cuerpo que puede usar como proyectiles explosivos."},
  {t:"m",q:"¿Cuál es el poder de Dupli-Kate?",o:["Volar a la velocidad de la luz","Duplicarse a sí misma indefinidamente","Manipular la gravedad","Volverse invisible"],a:1,exp:"Dupli-Kate puede crear copias perfectas de sí misma en grandes cantidades.",extra:"Sus duplicados comparten su conciencia y pueden coordinarse perfectamente en combate."},
  {t:"m",q:"¿Qué le ocurre a Monster Girl cada vez que se transforma?",o:["Gana poderes nuevos","Se rejuvenece físicamente","Pierde recuerdos","Aumenta de tamaño permanentemente"],a:1,exp:"Cada vez que Monster Girl se transforma en monstruo, su cuerpo humano se rejuvenece, haciéndola más joven.",extra:"Esto es una maldición: Monster Girl va rejuveneciendo de forma involuntaria con cada transformación."},
  {t:"m",q:"¿Cuál es el impactante secreto de Robot?",o:["Es un Viltrumita disfrazado","Es un niño deforme que pilota el robot desde un tanque","Es el clon de Cecil","Es una IA creada por el gobierno"],a:1,exp:"Robot es en realidad Rudy Conners, un joven con un cuerpo gravemente deformado que controla el robot de forma remota.",extra:"Este reveal es uno de los más memorables de la serie y cambia completamente la percepción del personaje."},
  {t:"m",q:"¿Cuál es el nombre real de Robot?",o:["Rudy Conners","Ryan Roberts","Carl Robins","Rudy Collins"],a:0,exp:"El verdadero nombre de Robot es Rudy Conners, quien vive en un tanque de soporte vital.",extra:"Rudy es un genio con una inteligencia excepcional que compensa sus limitaciones físicas con tecnología."},
  {t:"m",q:"¿Quién es Conquest en el universo de Invincible?",o:["Un héroe retirado de la GDA","Un Viltrumita mayor extremadamente peligroso","El padre de Thragg","El hermano de Omni-Man"],a:1,exp:"Conquest es un veterano Viltrumita de enorme poder enviado para someter a Mark.",extra:"La pelea entre Mark y Conquest casi mata al protagonista y es una de las más brutales del cómic."},
  {t:"m",q:"¿Qué caracteriza especialmente a Battle Beast?",o:["Es un Viltrumita rebelde","Es un guerrero alienígena que ama el combate por encima de todo","Es el mayor aliado de Mark","Es el creador de los Reanimen"],a:1,exp:"Battle Beast es un feroz guerrero alienígena cuya única pasión es encontrar oponentes dignos de combatir.",extra:"Battle Beast derrotó a todo el equipo de superhéroes él solo en una sola noche, algo casi sin precedentes."},
  {t:"m",q:"¿A cuántos héroes derrotó Battle Beast en una sola noche?",o:["Solo a dos héroes","Al equipo completo de superhéroes","Solo a Rex Splode","Solo a Robot"],a:1,exp:"Battle Beast derrotó al grupo completo de superhéroes en una sola noche, demostrando su poder brutal.",extra:"Esto lo convirtió en una de las amenazas más peligrosas no-Viltrumitas de la serie."},
  {t:"m",q:"¿Quién es Thragg?",o:["El padre de Nolan","El Gran Regente del Imperio Viltrumita","El líder de la Coalición de Planetas","El primer Viltrumita en llegar a la Tierra"],a:1,exp:"Thragg es el Gran Regente del Imperio Viltrumita y el principal antagonista Viltrumita de la historia.",extra:"Thragg es considerado el Viltrumita más poderoso en existencia, superando incluso a Nolan."},
  {t:"m",q:"¿Quién es Anissa en el universo de Invincible?",o:["Una heroína aliada de Mark","Una Viltrumita enviada a reproducirse con Mark","La madre de Thragg","Una espía de la GDA"],a:1,exp:"Anissa es una Viltrumita enviada por el Imperio con la misión de reproducirse con Mark para crear guerreros.",extra:"La escena de Anissa con Mark es una de las más polémicas y oscuras del cómic original."},
  {t:"m",q:"¿Cómo se llaman los clones que pelean entre sí sobre quién es el original?",o:["Los Clones Bowen","Los Mellizos Mauler","Los Gemelos Rex","Los Duplicados Mauler"],a:1,exp:"Los Mellizos Mauler son dos clones que constantemente argumentan sobre cuál de los dos es el original.",extra:"Su incapacidad para resolver este debate es un elemento cómico recurrente de la serie."},
  {t:"m",q:"¿Quién es Titan en el universo de Invincible?",o:["Un héroe original de la GDA","Un villano menor que trabaja para Machine Head y luego se convierte en héroe","El hermano de Battle Beast","Un Viltrumita renegado"],a:1,exp:"Titan comienza como villano trabajando para Machine Head, pero eventualmente cambia de bando.",extra:"Titan tiene superfuerza y su piel se vuelve como roca cuando activa sus poderes."},
  {t:"m",q:"¿Quién creó el cómic de Invincible?",o:["Todd McFarlane","Robert Kirkman","Jim Lee","Erik Larsen"],a:1,exp:"Robert Kirkman es el creador de Invincible, publicado originalmente por Image Comics.",extra:"Kirkman también es conocido por crear The Walking Dead, otra serie icónica de Image Comics."},
  {t:"m",q:"¿En qué editorial se publicó originalmente el cómic de Invincible?",o:["Marvel Comics","DC Comics","Image Comics","Dark Horse Comics"],a:2,exp:"Invincible fue publicado por Image Comics, la editorial fundada en 1992 por creadores que querían conservar los derechos de sus obras.",extra:"Image Comics fue fundada por figuras como Todd McFarlane, Jim Lee y Rob Liefeld, entre otros."},
  {t:"m",q:"¿Quién da voz a Omni-Man en la serie animada de Amazon Prime?",o:["Bryan Cranston","J.K. Simmons","Arnold Schwarzenegger","Liam Neeson"],a:1,exp:"J.K. Simmons presta su voz a Omni-Man en la adaptación animada de Amazon Prime.",extra:"J.K. Simmons es famoso por ganar el Oscar por Whiplash y por interpretar al J. Jonah Jameson."},
  {t:"m",q:"¿Quién da voz a Mark Grayson en la serie animada de Amazon Prime?",o:["Andrew Garfield","Tom Holland","Steven Yeun","Charlie Cox"],a:2,exp:"Steven Yeun, famoso por The Walking Dead, da voz a Mark Grayson en la serie de Amazon.",extra:"Steven Yeun fue elegido para el papel gracias a su experiencia previa con el universo de Robert Kirkman."},
  {t:"m",q:"¿Quién da voz a Debbie Grayson en la serie animada de Amazon Prime?",o:["Sandra Oh","Cate Blanchett","Octavia Spencer","Viola Davis"],a:0,exp:"Sandra Oh, conocida por Grey's Anatomy y Killing Eve, da voz a Debbie Grayson.",extra:"La actuación de Sandra Oh durante las escenas de la revelación de Nolan fue muy elogiada."},
  {t:"m",q:"¿Quién es Allen el Alienígena?",o:["Un espía Viltrumita","Un representante de la Coalición de Planetas y amigo de Mark","El creador de los Reanimen","Un miembro del Teen Team"],a:1,exp:"Allen el Alienígena es un representante de la Coalición de Planetas que se convierte en amigo de Mark.",extra:"Allen inicialmente llega a la Tierra pensando que es otro planeta que necesita evaluación."},
  {t:"m",q:"¿Cuál era la misión original de Allen el Alienígena en la Tierra?",o:["Espiar a los Viltrumitas","Evaluar las defensas del planeta para la Coalición","Reclutar a Mark para la Coalición","Traer mensajes del Imperio Viltrumita"],a:1,exp:"Allen visitaba planetas para evaluar si sus héroes podían resistir una posible invasión Viltrumita.",extra:"Allen repite este proceso en muchos planetas como parte de su trabajo rutinario para la Coalición."},
  {t:"m",q:"¿Cómo se llama la primera novia de Mark en el instituto?",o:["Samantha Eve","Amber Bennett","Kate Cha","Sandra Moore"],a:1,exp:"Amber Bennett es la primera novia formal de Mark durante sus años en el instituto.",extra:"Amber no conoce inicialmente la identidad de Mark como Invincible, lo que genera tensión en la relación."},
  {t:"m",q:"¿Quién es Oliver Grayson?",o:["El primo de Mark","El medio hermano de Mark, hijo de Nolan con una mujer alien","El mejor amigo secreto de Nolan","El clon de Mark"],a:1,exp:"Oliver es el medio hermano de Mark, hijo que Nolan tuvo con una mujer de un planeta alienígena.",extra:"Oliver crece mucho más rápido que los humanos debido a la biología de su madre."},
  {t:"m",q:"¿Cuál es el apodo superheroico de Oliver Grayson?",o:["Mini-Man","Young Omni-Man","Kid Invincible","Joven Viltrumita"],a:1,exp:"Oliver adopta el nombre de Young Omni-Man como superhéroe.",extra:"Oliver tiene una visión más drástica de la justicia que su hermano Mark."},
  {t:"m",q:"¿Qué es la Guerra Viltrumita?",o:["Una guerra civil dentro del Imperio Viltrumita","La guerra final entre la Tierra y el Imperio Viltrumita","El conflicto entre Mark y Thragg","La invasión de la Tierra por los Sequids"],a:1,exp:"La Guerra Viltrumita es el conflicto a gran escala entre los aliados de la Tierra y el Imperio Viltrumita.",extra:"Representa el arco culminante de la primera gran etapa del cómic de Invincible."},
  {t:"m",q:"¿Qué son los Sequids?",o:["Robots de combate Viltrumitas","Alienígenas parásitos de Marte que controlan mentes","Los creadores de los Reanimen","Guerreros de la Coalición de Planetas"],a:1,exp:"Los Sequids son alienígenas parásitos que habitan en Marte y pueden controlar las mentes de sus huéspedes.",extra:"Los Sequids representan una de las amenazas más únicas del universo de Invincible."},
  {t:"m",q:"¿Con qué propósito Image Comics fue fundada por sus creadores?",o:["Para competir directamente con DC Comics","Para que los creadores conservaran los derechos de sus obras","Para publicar solo cómics de autor europeo","Para ser la editorial de los cómics de videojuegos"],a:1,exp:"Image Comics fue fundada en 1992 para que los artistas y escritores pudieran conservar la propiedad de sus creaciones.",extra:"Este modelo fue revolucionario en una industria donde Marvel y DC eran dueñas de todos sus personajes."},
  {t:"m",q:"¿Quién es Terra Grayson?",o:["La madre de Nolan Grayson","La hija futura de Mark Grayson","La hermana de Atom Eve","La primera mujer Viltrumita mencionada en el cómic"],a:1,exp:"Terra Grayson es la hija de Mark y Atom Eve, quien aparece en el futuro de la historia.",extra:"Terra hereda poderes tanto de su padre Viltrumita como de la capacidad de manipulación de materia de Eve."},
  {t:"m",q:"¿Qué hace única a la longevidad de los Viltrumitas?",o:["Viven exactamente 500 años","Tienen longevidad extrema y envejecen muy lentamente","Son inmortales y no pueden morir","Rejuvenecen cada 100 años"],a:1,exp:"Los Viltrumitas tienen una longevidad extrema y envejecen muy lentamente comparado con los humanos.",extra:"Nolan tiene miles de años a pesar de parecer un hombre de mediana edad."},
  {t:"m",q:"¿Cuáles son los poderes principales de Mark Grayson como Viltrumita?",o:["Telepatía, invisibilidad y velocidad","Fuerza sobrehumana, vuelo y durabilidad extrema","Control de elementos y regeneración rápida","Manipulación del tiempo y viaje dimensional"],a:1,exp:"Los Viltrumitas como Mark poseen fuerza sobrehumana, capacidad de vuelo y una durabilidad extrema.",extra:"Con el tiempo, Mark descubre que puede volar en el espacio y sobrevivir en el vacío."},
  {t:"m",q:"¿Cuándo comenzó a publicarse el cómic de Invincible?",o:["1998","2000","2003","2005"],a:2,exp:"Invincible comenzó a publicarse en 2003 por Image Comics.",extra:"La serie duró hasta 2018, concluyendo con el issue #144."},
  {t:"m",q:"¿Con qué otro famoso cómic de Robert Kirkman se compara frecuentemente Invincible?",o:["Saga","The Walking Dead","Prophet","Spawn"],a:1,exp:"Invincible se compara frecuentemente con The Walking Dead, otra obra maestra de Robert Kirkman.",extra:"Ambas series son consideradas los trabajos más importantes de Kirkman como escritor."},
  {t:"m",q:"¿Cuántos issues duró el cómic original de Invincible?",o:["100 issues","120 issues","133 issues","144 issues"],a:3,exp:"El cómic de Invincible concluyó con el issue #144, publicado en 2018.",extra:"La serie tuvo una conclusión planificada por Kirkman, a diferencia de muchos cómics que se prolongan indefinidamente."},
  {t:"m",q:"¿En qué plataforma de streaming se estrenó la serie animada de Invincible?",o:["Netflix","Disney+","Amazon Prime Video","HBO Max"],a:2,exp:"La serie animada de Invincible se estrenó en Amazon Prime Video.",extra:"Amazon apostó fuerte por la serie y fue renovada por múltiples temporadas desde su estreno."},
  {t:"m",q:"¿En qué año se estrenó la serie animada de Invincible en Amazon Prime?",o:["2019","2020","2021","2022"],a:2,exp:"La serie animada de Invincible se estrenó en 2021 en Amazon Prime Video.",extra:"La serie fue un éxito inmediato gracias a su fidelidad al material fuente y su violencia sin censura."},
  {t:"m",q:"¿Por qué se dice que el issue #1 de Invincible enganchó a los lectores con su revelación final?",o:["Reveló que Mark es en realidad un Viltrumita","Mostró que Omni-Man asesina a los Guardianes del Globo al final","Presentó a Thragg como el villano principal","Reveló que Cecil es el padre biológico de Mark"],a:1,exp:"El issue #1 termina con la impactante escena de Omni-Man masacrando a los Guardianes del Globo.",extra:"Esta revelación al final del primer número hizo que los lectores regresaran inmediatamente por el segundo."},
  {t:"m",q:"¿Qué le sucedió al equipo original de los Guardianes del Globo?",o:["Se retiraron todos al mismo tiempo","Fueron asesinados por Omni-Man","Fueron capturados por los Viltrumitas","Se disolvieron por disputas internas"],a:1,exp:"Omni-Man masacra al equipo original de los Guardianes del Globo al inicio de la historia.",extra:"Esta brutal masacre desencadena la investigación de Cecil y eventualmente la revelación sobre Nolan."},
  {t:"m",q:"¿Quién forma el nuevo equipo de los Guardianes del Globo tras la masacre?",o:["Solo Mark Grayson","Cecil Stedman selecciona nuevos héroes incluyendo miembros del Teen Team","Los Viltrumitas crean un equipo sustituto","Los Mellizos Mauler forman el nuevo equipo"],a:1,exp:"Cecil forma un nuevo equipo de Guardianes del Globo incorporando héroes como miembros del Teen Team.",extra:"La formación del nuevo equipo es parte del esfuerzo de la GDA por mantener protegida la Tierra."},
  {t:"m",q:"¿Qué relación romántica se desarrolla entre Mark y Atom Eve?",o:["Son solo amigos desde la infancia","Eve se convierte en la pareja romántica principal de Mark","Mark rechaza a Eve para estar con Amber","Eve se casa con Rex Splode ignorando a Mark"],a:1,exp:"Atom Eve termina convirtiéndose en la relación romántica más importante y duradera de Mark Grayson.",extra:"La relación entre Mark y Eve es uno de los ejes emocionales centrales de todo el cómic."},
  {t:"m",q:"¿Cuál era la rivalidad principal de Rex Splode con Mark Grayson?",o:["Competían por ser el mejor luchador","Rivalizaban por el amor de Atom Eve","Competían por el liderazgo del Teen Team","Peleaban por quién tenía más poderes"],a:1,exp:"Rex Splode y Mark Grayson rivalizaban especialmente por la atención romántica de Atom Eve.",extra:"Esta tensión creó una dinámica complicada dentro del Teen Team durante varios arcos de la historia."},
  {t:"m",q:"¿Qué le ocurre a Debbie cuando descubre la verdad sobre Nolan?",o:["Lo perdona inmediatamente y sigue con él","Debe lidiar con la traición y el hecho de que su matrimonio fue una mentira","Huye del planeta con Mark","Se convierte en agente de la GDA"],a:1,exp:"Debbie debe procesar que su vida entera fue construida sobre una mentira y que Nolan la usó para su misión Viltrumita.",extra:"El arco emocional de Debbie es uno de los más humanos y conmovedores de toda la serie."},
  {t:"m",q:"¿Qué tipo de proyecto secreto son los Reanimen en términos de materiales usados?",o:["Son robots de metal puro","Combinan partes humanas con implantes cibernéticos","Son clones genéticos puros","Son fantasmas controlados tecnológicamente"],a:1,exp:"Los Reanimen son cadáveres humanos reanimados y combinados con tecnología cibernética avanzada.",extra:"Cecil usa los Reanimen como una herramienta defensiva aunque su naturaleza es profundamente antiética."},
  {t:"m",q:"¿Qué hace que la adaptación animada de Invincible sea distinta a otros superhéroes animados?",o:["Es completamente infantil y sin violencia","Mantiene la violencia brutal y las temáticas adultas del cómic original","Es una historia de comedia","Está en blanco y negro para respetar el cómic"],a:1,exp:"La serie animada de Invincible se distingue por mantener la violencia extrema y los temas adultos del cómic.",extra:"Esto fue un punto de venta importante, diferenciándola de otras adaptaciones animadas de superhéroes."},
  {t:"m",q:"¿Cuál es la diferencia más notable entre la serie animada y el cómic original?",o:["La serie no incluye personajes como Allen el Alienígena","La serie expande algunos personajes y arcos secundarios con más profundidad","La serie termina antes del issue #11 del cómic","La serie animada ignora completamente a los Viltrumitas"],a:1,exp:"La serie animada expande y profundiza arcos secundarios que el cómic trataba más brevemente.",extra:"Esto permite una experiencia complementaria para quienes ya conocen el material original."},
  {t:"m",q:"¿Cómo manipula Cecil Stedman a Mark Grayson?",o:["Lo amenaza directamente con violencia","Lo usa como herramienta prometiéndole información y recursos","Le borra los recuerdos regularmente","Lo chantajea con la vida de su madre"],a:1,exp:"Cecil manipula a Mark ofreciéndole recursos, información y la falsa sensación de trabajar como iguales.",extra:"La relación entre Cecil y Mark es compleja y llena de desconfianza mutua que crece a lo largo de la serie."},
  {t:"m",q:"¿Qué planeta habitan los Sequids naturalmente?",o:["La Luna","Marte","Venus","Un asteroide entre Marte y Júpiter"],a:1,exp:"Los Sequids son los alienígenas parásitos que habitan originalmente en Marte.",extra:"Su capacidad de controlar mentes los hace extremadamente peligrosos para cualquier forma de vida inteligente."},
  {t:"m",q:"¿Cómo describe la Coalición de Planetas su misión principal?",o:["Conquistar nuevos mundos para sus miembros","Resistir y combatir la expansión del Imperio Viltrumita","Comerciar entre planetas civilizados","Estudiar razas alienígenas en el universo"],a:1,exp:"La Coalición de Planetas existe principalmente para resistir la expansión conquistadora del Imperio Viltrumita.",extra:"Allen el Alienígena es uno de sus miembros más activos en busca de aliados contra los Viltrumitas."},
  {t:"m",q:"¿En qué se diferencia Mark de otros Viltrumitas en términos de valores?",o:["Mark no tiene ninguna diferencia con ellos","Mark adoptó los valores humanos y rechaza la brutalidad Viltrumita","Mark es más poderoso que cualquier Viltrumita","Mark sigue las órdenes de Thragg a diferencia de los rebeldes"],a:1,exp:"Mark adoptó valores humanos al crecer en la Tierra y rechaza la ideología conquistadora y brutal Viltrumita.",extra:"Esta dualidad entre su herencia Viltrumita y sus valores humanos es el conflicto central de su personaje."},
  {t:"m",q:"¿Qué le dice Nolan a Mark durante su pelea sobre el futuro de la humanidad?",o:["Que los humanos merecen ser libres","Que los humanos son inferiores y serán esclavizados","Que Mark debería huir con él","Que la GDA es el verdadero enemigo de la humanidad"],a:1,exp:"Nolan le dice a Mark que los humanos son seres inferiores y que el Imperio los dominará, minimizando su valor.",extra:"Este discurso es lo que hace que Mark se resista y enfrente a su padre en combate."},
  {t:"m",q:"¿Por qué Nolan finalmente abandona su pelea con Mark?",o:["Porque Mark lo vence definitivamente","Porque Cecil interviene con armas especiales","Porque las palabras de Mark lo hacen dudar y se va llorando","Porque los otros Viltrumitas lo llaman de vuelta"],a:2,exp:"Las palabras de Mark sobre su vida juntos hacen que Nolan dude, y se va volando llorando sin poder terminar el combate.",extra:"Este momento es increíblemente emotivo y muestra que Nolan aún tiene sentimientos hacia su familia."},
  {t:"m",q:"¿Con qué equipo de superhéroes parodia Invincible a los Guardianes del Globo?",o:["La Liga de la Justicia de DC Comics","Los Vengadores de Marvel","Los X-Men","El Hombre Araña"],a:0,exp:"Los Guardianes del Globo son claramente una parodia de la Liga de la Justicia de DC Comics.",extra:"Sus miembros originales tienen poderes y apariencias que evocan directamente a Superman, Batman, Wonder Woman y otros."},
  {t:"m",q:"¿Qué papel juega Black Samson en el universo de Invincible?",o:["Es el director secreto de la GDA","Es un miembro poderoso de los Guardianes del Globo","Es el mentor de Mark desde el principio","Es un Viltrumita disfrazado de humano"],a:1,exp:"Black Samson es un superhéroe de gran poder que forma parte de los Guardianes del Globo.",extra:"Black Samson tiene un traje que amplifica sus capacidades y es uno de los héroes más respetados del equipo."},
  {t:"m",q:"¿Qué pasó con Amber Bennett y su relación con Mark?",o:["Se casaron y tienen hijos juntos","Su relación terminó principalmente por los secretos de Mark","Amber muere durante la Guerra Viltrumita","Amber se convierte en villana al final del cómic"],a:1,exp:"La relación de Mark con Amber termina en gran parte debido a los secretos que Mark le ocultaba sobre ser Invincible.",extra:"Amber eventualmente aprende la verdad pero la relación ya está demasiado dañada para continuar."},
  {t:"m",q:"¿Qué hace Nolan en el planeta de los Thraxans que complica aún más su historia?",o:["Funda una colonia Viltrumita","Forma una familia con una mujer local y tiene a Oliver","Traiciona al Imperio Viltrumita públicamente","Se vuelve rey del planeta"],a:1,exp:"Nolan forma una familia con una mujer Thraxana y tiene a Oliver antes de que transcurra mucho tiempo.",extra:"Los Thraxans tienen vidas muy cortas, así que su familia local envejece y muere mucho más rápido que Nolan."},
  {t:"m",q:"¿Qué aspecto diferencia visualmente el cómic de Invincible de otros superhéroes del mismo período?",o:["Su estilo completamente digital sin tinta","Sus colores vibrantes y brillantes en contraste con su violencia extrema","Su estilo en blanco y negro artístico","Sus páginas sin bordes en los paneles"],a:1,exp:"Invincible es famoso por sus colores vibrantes y casi cartoonescos, lo que contrasta brutalmente con su contenido violento.",extra:"Este contraste visual es intencional y añade un impacto mayor a las escenas de acción violenta."},
  {t:"m",q:"¿Cómo contribuyó el dibujante Ryan Ottley al éxito de Invincible?",o:["Solo dibujó los primeros 10 issues","Fue el dibujante principal durante la mayor parte de la serie","Solo dibujó las portadas","Creó el diseño de los Viltrumitas exclusivamente"],a:1,exp:"Ryan Ottley fue el dibujante principal de Invincible durante la mayor parte de su publicación.",extra:"La colaboración entre Kirkman y Ottley fue fundamental para el éxito y la identidad visual de la serie."},
  {t:"m",q:"¿Qué sucede con Nolan después de abandonar la Tierra?",o:["Regresa inmediatamente al Imperio Viltrumita","Es capturado y encarcelado en el planeta Thrax","Vaga por el universo antes de ser capturado por los Viltrumitas","Muere en el espacio poco después de la pelea"],a:2,exp:"Después de abandonar la Tierra, Nolan vaga por el espacio y eventualmente es capturado por los Viltrumitas.",extra:"Su captura inicia una nueva fase de la historia donde Mark lidia con las consecuencias de las acciones de su padre."},
  {t:"m",q:"¿Cuál fue la reacción de la crítica hacia la temporada 1 de la serie animada de Invincible?",o:["Fue muy negativa por su violencia excesiva","Fue extremadamente positiva, especialmente por el último episodio","Fue mediocre, considerada inferior al cómic","No hubo cobertura crítica significativa"],a:1,exp:"La temporada 1 fue aclamada por la crítica, especialmente el último episodio con la pelea de Omni-Man.",extra:"La serie consiguió una puntuación muy alta en Rotten Tomatoes y se convirtió en fenómeno cultural."},
  {t:"m",q:"¿Qué frase icónica repite Omni-Man durante su pelea con Mark?",o:["Eres más Viltrumita de lo que crees","Think, Mark!","Los humanos son nuestra familia ahora","El Imperio no puede saberlo"],a:1,exp:"'Think, Mark!' se convirtió en una frase icónica del episodio final de la primera temporada.",extra:"La frase fue tan memorable que se volvió un meme popular en internet tras el estreno."},
  {t:"m",q:"¿Qué representa el Imperio Viltrumita para el universo de Invincible?",o:["Una utopía intergaláctica benevolente","Una potencia conquistadora brutal que domina planetas enteros","Una confederación de planetas aliados","Una organización de superhéroes intergalácticos"],a:1,exp:"El Imperio Viltrumita es una potencia conquistadora que somete y controla planetas por la fuerza.",extra:"Su ideología de dominio lo convierte en la principal amenaza para la libertad galáctica en el universo de Invincible."},
  {t:"m",q:"¿Cuánto tiempo lleva Nolan viviendo en la Tierra antes de los eventos del cómic?",o:["10 años","20 años","Aproximadamente 20 años con Debbie","Miles de años con diferentes identidades"],a:2,exp:"Nolan lleva aproximadamente 20 años viviendo en la Tierra y casado con Debbie antes del inicio del cómic.",extra:"Para un Viltrumita, 20 años son relativamente pocos dada su longevidad extrema de miles de años."},
  {t:"m",q:"¿Qué hace que la pelea entre Invincible y Omni-Man sea memorablemente brutal?",o:["El uso de armas de destrucción masiva","Omni-Man arrastra a Mark por ciudades enteras aplastando civiles","Mark usa poderes que aún no había mostrado","Cecil ataca a ambos desde el exterior"],a:1,exp:"Durante la pelea, Omni-Man arrastra a Mark destruyendo todo a su paso, incluyendo muchas víctimas civiles.",extra:"La secuencia muestra lo desenfrenada y devastadora que puede ser la violencia de seres de ese nivel de poder."},
  {t:"m",q:"¿Qué rol cumple la GDA en la Tierra del universo Invincible?",o:["Es solo una organización benéfica para superhéroes","Es la agencia gubernamental que supervisa y apoya a los superhéroes en la Tierra","Es el brazo armado secreto del Imperio Viltrumita","Es una corporación privada que comercia con tecnología alien"],a:1,exp:"La GDA es la organización gubernamental encargada de supervisar las actividades superhumanas y defender la Tierra.",extra:"Cecil Stedman la dirige con mano de hierro y métodos muy cuestionables éticamente."},
  {t:"m",q:"¿Cuándo Mark descubre la verdad sobre su padre, cuál es su primera reacción?",o:["Inmediatamente llama a Cecil para reportarlo","Confronta directamente a su padre exigiendo la verdad","Se va del planeta a buscar ayuda","Se une a su padre para proteger su familia"],a:1,exp:"Mark confronta directamente a Nolan cuando conoce la verdad, lo que desencadena su brutal pelea.",extra:"La confrontación es inevitable dado el carácter directo de Mark y su incapacidad de aceptar la traición."},
  {t:"m",q:"¿Qué rompe la resolución de Nolan durante la pelea con Mark?",o:["Ver que Mark es más fuerte de lo esperado","Recibir un llamado urgente del Imperio Viltrumita","Las palabras de Mark recordándole los momentos familiares compartidos","La intervención de Debbie que aparece en el lugar"],a:2,exp:"Mark le recuerda a Nolan memorias de su vida juntos como familia, lo que quiebra emocionalmente a Nolan.",extra:"Nolan no puede matar a su propio hijo y se va, mostrando que su amor humano pudo más que su programación Viltrumita."},
  {t:"m",q:"¿Cómo termina el issue #144, el último número del cómic de Invincible?",o:["Con una batalla épica abierta sin resolución","Con Mark mirando hacia el futuro junto a su familia en un final esperanzador","Con la muerte de Mark Grayson","Con la conquista final de la Tierra por los Viltrumitas"],a:1,exp:"El cómic concluye con Mark contemplando el futuro junto a su familia en un tono esperanzador y satisfactorio.",extra:"Kirkman eligió un final positivo que honrara el viaje del personaje y diera cierre emocional a sus lectores."},
  {t:"m",q:"¿Qué representa la Coalición de Planetas como contrapeso al Imperio Viltrumita?",o:["Es solo una organización burocrática sin poder real","Es la alianza de planetas que resiste y combate la expansión Viltrumita","Es el gobierno galáctico que regula a todos los planetas","Es una organización comercial que hace negocios con los Viltrumitas"],a:1,exp:"La Coalición de Planetas es la resistencia organizada contra el Imperio Viltrumita, reuniendo mundos libres.",extra:"Su existencia da esperanza a los planetas amenazados y proporciona aliados clave a Mark en su lucha."},
  {t:"m",q:"¿Qué hace que los Viltrumitas sean difíciles de matar además de su durabilidad?",o:["Son inmortales por su genética","Su longevidad extrema significa que tienen siglos de experiencia en combate","Regeneran cualquier herida en segundos","Su piel es impenetrable para cualquier material conocido"],a:1,exp:"Los siglos de experiencia acumulada en combate hacen que los Viltrumitas sean guerreros extraordinariamente hábiles.",extra:"Incluso un Viltrumita físicamente más débil puede vencer a un oponente más fuerte con su experiencia."},
  {t:"m",q:"¿Qué hace especial a la forma en que Invincible trata la identidad secreta del protagonista?",o:["Mark nunca tiene identidad secreta, siempre es público","La identidad secreta es complicada por sus relaciones y las presiones de su doble vida","Mark abandona su identidad secreta en el primer número","La GDA maneja su identidad públicamente para él"],a:1,exp:"La identidad secreta de Mark crea complicaciones reales en sus relaciones personales y en su vida cotidiana.",extra:"A diferencia de Superman o Spider-Man, las consecuencias de la identidad secreta se desarrollan de forma más realista."},
  {t:"m",q:"¿Por qué Atom Eve abandona inicialmente la vida de superheroína?",o:["Porque sus poderes desaparecen","Porque decide que puede hacer más bien ayudando a personas con sus poderes de forma directa","Porque Cecil la obliga a retirarse","Porque Mark le pide que deje de arriesgarse"],a:1,exp:"Eve decide que puede hacer más bien usando sus poderes para ayudar directamente a personas en necesidad.",extra:"Esta decisión muestra la madurez del personaje y su cuestionamiento del modelo tradicional de superhéroe."},
  {t:"m",q:"¿Cuál fue el impacto de Image Comics en la industria de los cómics cuando se fundó?",o:["Apenas tuvo impacto en la industria","Revolucionó la industria al demostrar que los creadores podían tener éxito conservando sus derechos","Quebró rápidamente y cerró en sus primeros años","Fue absorbida por Marvel poco después de fundarse"],a:1,exp:"Image Comics revolucionó la industria demostrando que los creadores podían tener éxito económico conservando sus derechos.",extra:"Su fundación en 1992 cambió la dinámica de poder entre creadores y editoriales en la industria del cómic."},
  {t:"m",q:"¿Qué mensaje sobre la responsabilidad transmite el personaje de Cecil a los lectores?",o:["La responsabilidad exige sacrificar cualquier ética","La responsabilidad sin ética conduce a convertirse en lo que uno dice combatir","La responsabilidad es un concepto relativo y Cecil está completamente justificado","La responsabilidad solo existe para los superhéroes activos"],a:1,exp:"Cecil muestra que una responsabilidad sin ética puede llevar a convertirse en una amenaza similar a la que se combate.",extra:"Su personaje es una advertencia sobre cómo las buenas intenciones sin escrúpulos pueden corromperse."},
  {t:"m",q:"¿Cómo impacta la revelación de la identidad de Invincible en la vida de William?",o:["William rechaza a Mark completamente al enterarse","William acepta la verdad y mantiene su amistad con Mark, adaptándose a esta nueva realidad","William se convierte en sidekick de Mark inmediatamente","William reporta la identidad de Mark a la GDA"],a:1,exp:"William acepta la revelación y mantiene su amistad con Mark, adaptándose a la nueva realidad.",extra:"Su lealtad inquebrantable es una de las relaciones más estables y reconfortantes de la vida de Mark."},
  {t:"m",q:"¿Qué lección extrae Mark de su pelea con su padre Omni-Man?",o:["Que los Viltrumitas son invencibles y debe unirse a ellos","Que el poder sin valores morales conduce a la monstruosidad","Que debe entrenar más para superar a su padre","Que Cecil tenía razón sobre no confiar en Nolan"],a:1,exp:"Mark aprende que el poder sin valores morales y empatía conduce inevitablemente a la monstruosidad.",extra:"Esta lección moldea toda su filosofía como héroe y su resistencia a las presiones del Imperio Viltrumita."},
  {t:"m",q:"¿Qué aspecto de la cultura pop convirtió a Omni-Man en un ícono tras el estreno de la serie?",o:["Su diseño de traje copiado de Superman","La frase Think Mark y la escena de la paliza que se volvieron virales","Su voz en la serie animada","Su historia de amor con Debbie"],a:1,exp:"La escena de la paliza y la frase 'Think, Mark!' se viralizaron en internet convirtiéndose en íconos culturales.",extra:"J.K. Simmons recibió especial atención por su interpretación vocal que dio vida a Omni-Man."},
  {t:"m",q:"¿Qué representa Machine Head en el universo de Invincible?",o:["Es un cyborg villano que lidera una red criminal de superpoderes","Es un aliado secreto de la GDA","Es el creador de los Mellizos Mauler","Es el jefe del ejército Viltrumita en la Tierra"],a:0,exp:"Machine Head es un villano criminal con una cabeza cyborg que dirige una organización criminal de supervillanos.",extra:"Sus operaciones incluyen contratar superhéroes y villanos para sus propósitos criminales."},
  {t:"m",q:"¿Cuándo Nolan regresa a la historia tras su huida, cuál es su actitud hacia Mark?",o:["Llega furioso dispuesto a completar su misión Viltrumita","Regresa arrepentido y buscando redimirse ante su familia","Regresa como enemigo declarado de la Tierra","Regresa enviado por Thragg para capturar a Mark"],a:1,exp:"Cuando Nolan regresa, lo hace con una actitud de arrepentimiento y buscando redimirse ante Mark y la familia.",extra:"Su arco de redención es central en la segunda mitad de la serie."},
  {t:"m",q:"¿Por qué Invincible se considera una obra influyente para los cómics independientes?",o:["Fue el primer cómic publicado digitalmente","Demostró que los cómics independientes de superhéroes podían competir en calidad con Marvel y DC","Introdujo el formato de miniserie de 12 números","Fue el primer cómic en venderse en supermercados"],a:1,exp:"Invincible demostró que un cómic independiente de superhéroes podía alcanzar la misma calidad narrativa que los grandes del género.",extra:"Su éxito abrió puertas para otros creadores que querían hacer superhéroes fuera de Marvel y DC."},
  {t:"m",q:"¿Qué hace que la serie de Amazon no sea apta para audiencias jóvenes?",o:["Contiene lenguaje inapropiado únicamente","Tiene escenas de violencia extrema y gore además de temáticas adultas complejas","Solo tiene temas románticos para adultos","Tiene referencias políticas muy específicas"],a:1,exp:"La serie incluye violencia extrema y gore, temáticas adultas como traición, abuso y consecuencias psicológicas.",extra:"La serie tiene clasificación para adultos y fue diseñada deliberadamente para diferenciarse de los superhéroes infantiles."},
  {t:"m",q:"¿Qué descubrimiento hace Mark sobre su capacidad de sobrevivir en el espacio?",o:["Necesita un traje especial para respirar","Puede sobrevivir en el vacío del espacio sin protección especial","Solo puede estar 5 minutos en el espacio","Necesita una burbuja de aire generada por sus poderes"],a:1,exp:"Mark descubre que como Viltrumita puede sobrevivir en el vacío del espacio sin necesitar respirar.",extra:"Esta capacidad le permite viajar por el universo y ser parte de conflictos interestelares."},
  {t:"m",q:"¿Qué relación tiene el universo de Invincible con otros personajes de Image Comics?",o:["Invincible no comparte universo con ningún otro personaje de Image","El universo de Invincible coexiste con otros personajes de Image Comics como Savage Dragon","Invincible es un personaje prestado de Marvel a Image","Kirkman creó todos los personajes de Image Comics"],a:1,exp:"El universo de Invincible comparte continuidad con otros personajes de Image Comics como Savage Dragon.",extra:"Esto permitió crossovers y apariciones especiales entre las diferentes series de Image."},
  {t:"m",q:"¿Qué tipo de reflexión hace Mark sobre su identidad entre ser humano y ser Viltrumita?",o:["Acepta completamente ser Viltrumita y rechaza su humanidad","Rechaza completamente la herencia Viltrumita y se considera puramente humano","Lucha por integrar ambas partes de sí mismo y define sus propios valores","Deja que la GDA decida qué tipo de ser debe ser"],a:2,exp:"Mark pasa la historia integrando su herencia dual, llegando a definir sus propios valores en lugar de seguir a ningún lado.",extra:"Esta lucha de identidad es el arco más profundo del personaje y el que más conecta con lectores adolescentes."},
  {t:"m",q:"¿Qué hace especial a la serie animada respecto a sus secuencias de acción?",o:["La acción es más calmada que el cómic para ser apropiada para todos","Las secuencias de acción son brutalmente detalladas mostrando todo el daño y la sangre","La animación usa CGI completo sin animación 2D tradicional","Las peleas son muy rápidas y sin violencia visible"],a:1,exp:"La animación de Amazon reproduce fielmente la brutalidad del cómic con secuencias de acción detalladas y sangrientas.",extra:"Esto fue posible por ser una producción para adultos sin las restricciones de una serie familiar."},
  {t:"m",q:"¿Qué muestra la historia de Nolan sobre el conflicto entre el deber y el amor?",o:["El deber siempre gana sobre el amor en la historia de Nolan","El amor por su familia eventualmente supera su programación y deber hacia el Imperio","Nolan nunca siente amor por su familia, solo finge","El amor y el deber coexisten perfectamente en Nolan sin conflicto"],a:1,exp:"La historia de Nolan muestra cómo el amor genuino que desarrolló por su familia supera su programación como agente del Imperio.",extra:"Esta tensión humana es lo que convierte a Omni-Man en uno de los antagonistas más complejos del género."},
  {t:"m",q:"¿Qué rol tiene Amber Bennett en el desarrollo emocional de Mark?",o:["Es irrelevante para el desarrollo de Mark","Es la primera relación romántica seria que le enseña a equilibrar su vida doble","Es quien le revela su identidad viltrumita a la GDA","Es la figura que lo convence de luchar contra su padre"],a:1,exp:"Amber es la primera relación romántica seria de Mark y le enseña los problemas de equilibrar una vida doble.",extra:"Aunque la relación termina, la experiencia con Amber forma a Mark para su eventual relación con Eve."},
  {t:"m",q:"¿Qué le enseña la relación de Mark con Eve sobre el sacrificio y el apoyo mutuo?",o:["Que el amor romántico no puede existir entre superhéroes","Que el apoyo mutuo y el sacrificio son fundamentales en cualquier relación duradera","Que los superhéroes deben priorizar la misión sobre las relaciones personales","Que Eve siempre sacrifica más que Mark en su relación"],a:1,exp:"La relación de Mark y Eve muestra que el apoyo mutuo y la disposición al sacrificio son fundamentales en relaciones duraderas.",extra:"Ambos salvan la vida del otro en múltiples ocasiones y crecen juntos como personas y como héroes."},
  {t:"m",q:"¿Cuál es la última gran amenaza que Mark enfrenta antes del final del cómic?",o:["Una segunda invasión de los Mellizos Mauler","El conflicto final con Thragg que determina el futuro del Imperio Viltrumita","Una invasión de los Sequids a la Tierra","Cecil traicionando definitivamente a todos los héroes de la Tierra"],a:1,exp:"El conflicto final de Mark con Thragg determina el destino del Imperio Viltrumita y establece el final de la serie.",extra:"Este enfrentamiento es el clímax de todo el arco sobre los Viltrumitas que comenzó en el issue #1."},
  {t:"m",q:"¿Por qué Invincible es considerado uno de los mejores cómics de superhéroes de los años 2000?",o:["Por sus ventas récord que superaron a Marvel y DC","Por su combinación única de acción, profundidad emocional, consecuencias reales y escritura consistente","Solo por la violencia que lo diferenciaba del resto","Por sus crossovers con los grandes de Marvel y DC"],a:1,exp:"Invincible combina acción de alta calidad con profundidad emocional, consecuencias reales y escritura consistente durante 144 números.",extra:"Esta consistencia narrativa durante más de 15 años lo distingue de muchos cómics que pierden calidad con el tiempo."},
  {t:"m",q:"¿Qué representa en la historia el hecho de que Mark elija conscientemente no convertirse en un conquistador?",o:["Solo representa que Mark es más débil mentalmente que Nolan","Representa la capacidad humana de elegir valores propios por encima de la programación heredada","Representa la inferioridad de los valores humanos respecto a los Viltrumitas","No tiene representación simbólica particular en la narrativa"],a:1,exp:"La elección de Mark de no conquistar representa la capacidad de elegir valores propios por encima del legado o la programación recibida.",extra:"Este es el mensaje central de la serie: la identidad no la determina el origen sino las elecciones que uno hace."},
  {t:"m",q:"¿Cómo evoluciona la fuerza de Mark a lo largo del cómic?",o:["Sus poderes son iguales desde el principio hasta el final","Va creciendo progresivamente, especialmente después de casi morir en batallas","Pierde poderes cada vez que es herido gravemente","Su fuerza disminuye con la edad al ser Viltrumita"],a:1,exp:"Mark se vuelve progresivamente más poderoso, especialmente como resultado de casi morir en batallas extremas.",extra:"Las cicatrices de la guerra hacen a los Viltrumitas más fuertes, lo cual se aplica a Mark también."},
  {t:"m",q:"¿Cuál fue el número de ventas aproximado de Invincible en su mejor período?",o:["50,000 ejemplares mensuales","100,000 ejemplares mensuales","250,000 ejemplares mensuales","500,000 ejemplares mensuales"],a:0,exp:"Invincible vendía aproximadamente 50,000 ejemplares mensuales en sus mejores momentos de ventas.",extra:"Para Image Comics, estas cifras representaban un éxito significativo fuera del mainstream de Marvel y DC."},
  {t:"m",q:"¿Qué tiene de especial la relación entre Mark y Cecil en los primeros compases de la historia?",o:["Mark desconfía de Cecil desde el primer día","Mark y Cecil comienzan con una relación de relativa confianza y cooperación","Mark nunca interactúa directamente con Cecil","Cecil es el mentor heroico de Mark desde el principio"],a:1,exp:"Inicialmente Mark y Cecil trabajan juntos con relativa confianza antes de que Mark descubra los métodos más oscuros de Cecil.",extra:"Esta traición de confianza hace que la posterior tensión entre ellos sea más impactante."},
  {t:"m",q:"¿Qué papel tiene Cory Walker en el origen de Invincible?",o:["Fue el primer escritor antes de Kirkman","Dibujó los primeros 7 números del cómic","Creó el diseño de los Viltrumitas","Fue el editor durante toda la serie"],a:1,exp:"Cory Walker dibujó los primeros números de Invincible antes de que Ryan Ottley tomara las riendas.",extra:"Walker fue co-creador del diseño visual original de Invincible junto a Kirkman."},
  {t:"m",q:"¿Qué hace que Monster Girl sea un personaje único entre el Teen Team?",o:["Es la única con poderes mágicos","Su transformación tiene el efecto secundario de rejuvenecerla cada vez que la usa","Es la única sin ningún origen explicado","Es el único miembro no humano del equipo"],a:1,exp:"Monster Girl se distingue porque cada transformación en criatura la rejuvenece involuntariamente.",extra:"La maldición de rejuvenecer la condena a eventualmente convertirse en una niña muy pequeña por las transformaciones repetidas."},
  {t:"m",q:"¿Cómo describe Invincible el problema de los héroes que mueren comparado con Marvel y DC?",o:["Los héroes nunca mueren permanentemente","Los héroes pueden morir permanentemente y sus muertes tienen consecuencias duraderas","Solo los villanos mueren en la serie","Las muertes siempre son revertidas en el siguiente arco"],a:1,exp:"En Invincible los héroes pueden morir de forma permanente y sus muertes tienen consecuencias emocionales duraderas.",extra:"Esta disposición a matar personajes queridos añade tensión real a cada conflicto de la serie."},
  {t:"m",q:"¿Qué revela sobre Cecil su decisión de mantener los Reanimen en secreto de Mark?",o:["Que Cecil confía ciegamente en Mark","Que Cecil sabe que sus métodos serían inaceptables para Mark pero los hace igualmente","Que Cecil tiene miedo de la reacción del gobierno","Que los Reanimen son un proyecto completamente legal sin problemas éticos"],a:1,exp:"La decisión muestra que Cecil sabe que sus métodos son éticamente cuestionables pero los justifica por el bien mayor.",extra:"Esta actitud pragmática al costo de la ética define completamente el personaje de Cecil."},
  {t:"m",q:"¿Qué motivó a Robert Kirkman a crear un personaje superheroico como Invincible?",o:["Quería parodiar a Superman específicamente","Quería crear un cómic de superhéroes con consecuencias emocionales y físicas reales","Fue encargado por Image Comics para competir con Spider-Man","Quería adaptar una novela de ciencia ficción que había escrito"],a:1,exp:"Kirkman quería explorar qué pasaría si los superhéroes experimentaran consecuencias emocionales y físicas realistas.",extra:"Esta visión generó una de las series más maduras e impactantes del género superheroico."},
  {t:"m",q:"¿Qué representa la relación entre William y Mark para el desarrollo del personaje?",o:["William es solo un personaje secundario sin importancia","La amistad con William ancla a Mark en su humanidad y vida normal","William es quien entrena a Mark para controlar sus poderes","William es el vínculo secreto de Mark con la GDA"],a:1,exp:"La amistad de Mark con William lo ancla en la vida normal y en su humanidad, equilibrando su vida de superhéroe.",extra:"William representa el lado mundano de la vida de Mark que siempre existe paralelo a sus aventuras."},
  {t:"m",q:"¿Qué importancia tiene la academia del instituto en la historia de Mark?",o:["Es donde entrena sus poderes con Cecil","Es su instituto donde intenta llevar una vida normal","Es el cuartel general secreto de los Guardianes del Globo","Es donde conoce a Cecil Stedman por primera vez"],a:1,exp:"El instituto es donde Mark intenta llevar una vida normal como adolescente mientras equilibra su vida de superhéroe.",extra:"Las relaciones del instituto, especialmente con William y Amber, son el ancla de su humanidad."},
  {t:"m",q:"¿Qué establece Invincible en cuanto al legado de Robert Kirkman como escritor?",o:["Invincible fue su único éxito, Walking Dead fracasó","Junto con The Walking Dead establece a Kirkman como uno de los escritores de cómics más importantes de los 2000s","Kirkman consideró a Invincible su obra menor comparada con Walking Dead","Invincible fue un fracaso comercial que Kirkman abandonó rápidamente"],a:1,exp:"Invincible y The Walking Dead juntos establecen a Kirkman como uno de los escritores más importantes e influyentes de los 2000s.",extra:"Ambas series muestran su capacidad de crear personajes profundos en géneros muy diferentes."},
  {t:"m",q:"¿Qué tipo de amenaza representan los Mellizos Mauler para la sociedad?",o:["Son relativamente inofensivos a pesar de su apariencia amenazante","Son supervillanos con enorme fuerza que han causado enorme daño en sus confrontaciones","Son solo criminales de bajo perfil sin superpoderes reales","Son científicos que usan tecnología en lugar de fuerza bruta"],a:1,exp:"Los Mellizos Mauler son supervillanos extremadamente peligrosos con grandes capacidades físicas y científicas.",extra:"Su dinámica cómica existe junto a una genuina amenaza que los héroes toman muy en serio."},
  {t:"m",q:"¿Qué filosfía de conquista justifica el Imperio Viltrumita?",o:["La conquista es solo para explotar recursos de los planetas","La conquista trae civilización y orden a planetas inferiores","Solo conquistan planetas deshabitados","La conquista es un proceso electoral donde los planetas eligen unirse"],a:1,exp:"Los Viltrumitas justifican su conquista argumentando que traen civilización y orden a razas inferiores.",extra:"Esta justificación de superioridad racial es una crítica al imperialismo que Kirkman teje en la narrativa."},
  {t:"m",q:"¿Qué tiene de único la relación de Mark con la muerte de civiles durante sus batallas?",o:["Mark nunca lamenta las muertes civiles","Mark carga con la culpa de las muertes que ocurren durante sus combates","La GDA borra los recuerdos de Mark de las muertes","Los civiles nunca mueren en las batallas de Mark"],a:1,exp:"Mark carga con el peso psicológico de las muertes civiles que ocurren durante sus batallas.",extra:"Esta culpa y su procesamiento son parte del realismo emocional que distingue a Invincible."},
  {t:"m",q:"¿Qué diferencia fundamental hay entre la forma de pensar de Mark y la de Cecil?",o:["Mark quiere más violencia, Cecil quiere negociación","Mark cree en la justicia y la ética, Cecil cree que el fin justifica los medios","Mark quiere trabajar solo, Cecil quiere equipos grandes","Mark confía en los alienígenas, Cecil no"],a:1,exp:"Mark tiene una visión ética del heroísmo mientras Cecil adopta totalmente la filosofía de que el fin justifica los medios.",extra:"Este choque de filosofías es la fuente de la tensión permanente entre ambos personajes."},
  {t:"m",q:"¿Cuál fue la primera batalla importante de Mark como Invincible antes de conocer a Cecil?",o:["Contra los Mellizos Mauler","Contra Machine Head y sus mercenarios","Contra un villano escolar en su propio instituto","Contra el primer agente Viltrumita enviado a la Tierra"],a:0,exp:"Una de las primeras confrontaciones importantes de Mark es contra los Mellizos Mauler.",extra:"Esta batalla ayuda a establecer sus capacidades y lo introduce en el mundo más amplio de los superhéroes."},
  {t:"m",q:"¿Qué hace que el primer episodio de la temporada 1 sea tan engañoso para los espectadores nuevos?",o:["Presenta a Mark como un villano desde el principio","Parece un superhéroe estándar hasta el final donde muestra su oscuridad","Revela todos los secretos en el primer episodio","Muestra la muerte de Omni-Man al principio"],a:1,exp:"El primer episodio aparenta ser un cómic de superhéroes estándar y familiar antes de revelar su naturaleza oscura.",extra:"Esta estrategia narrativa es la misma que usa el cómic original, construyendo expectativas para romperlas."},
  {t:"m",q:"¿Cuántas temporadas de la serie animada de Invincible han sido producidas o anunciadas?",o:["Solo una temporada","Dos temporadas","Tres temporadas anunciadas o producidas","Cuatro temporadas"],a:2,exp:"Se anunciaron al menos tres temporadas de la serie animada, con Amazon comprometida con la adaptación a largo plazo.",extra:"El éxito de la primera temporada garantizó que Amazon renovara la serie para múltiples temporadas."},
  {t:"m",q:"¿Qué tienen en común los poderes de Mark con los de su padre Nolan?",o:["Son idénticos en todos los aspectos","Comparten los mismos poderes base Viltrumitas pero con diferentes niveles de experiencia","Mark tiene poderes que Nolan nunca manifestó","Solo comparten el vuelo, pero no la fuerza"],a:1,exp:"Mark y Nolan comparten exactamente los mismos poderes base Viltrumitas, pero Nolan tiene siglos más de práctica.",extra:"Con el tiempo, Mark alcanza y potencialmente supera el nivel de poder de Nolan."},
  {t:"m",q:"¿Cuál es el significado del nombre 'Invincible' para el personaje de Mark?",o:["Es el nombre que le dio el Imperio Viltrumita","Es el nombre que Cecil le asigna oficialmente","Es el nombre de héroe que Mark elige para sí mismo inspirado en su herencia","Es el nombre que Nolan le puso en secreto cuando nació"],a:2,exp:"Mark adopta el nombre Invincible como su identidad de héroe, inspirado en su herencia y su aspiración.",extra:"El nombre captura tanto su fortaleza como su determinación de ser un tipo diferente de héroe que su padre."},
  {t:"m",q:"¿Qué le ocurre a Eve cuando usa sus poderes al máximo y se agota?",o:["Pierde todos sus poderes permanentemente","Puede morir si usa demasiado poder de una vez","Solo necesita dormir para recuperarse","Sus poderes se vuelven incontrolables"],a:1,exp:"Eve puede morir si usa sus poderes más allá de sus límites, lo que hace que sus intervenciones al máximo sean muy arriesgadas.",extra:"Este límite añade tensión dramática a los momentos donde Eve usa todo su poder para salvar a alguien."},
  {t:"m",q:"¿Qué reflexión hace Mark sobre la responsabilidad de tener poderes al comenzar su carrera?",o:["Que los poderes son solo una herramienta sin obligaciones morales","Que tener poderes implica una responsabilidad activa de proteger a los demás","Que los poderes son una carga que desearía no tener","Que la GDA debe dictar todas sus decisiones con poderes"],a:1,exp:"Mark asume desde temprano que tener poderes implica una responsabilidad activa de usar esos poderes para proteger a otros.",extra:"Esta ética heroica genuina es lo que lo diferencia de la mentalidad conquistadora Viltrumita."},
  {t:"m",q:"¿Qué importancia tiene Donald Ferguson como personaje en la GDA?",o:["Es el co-director junto a Cecil","Es el asistente principal y mano derecha de Cecil Stedman","Es el científico jefe de los Reanimen","Es el enlace entre la GDA y el gobierno"],a:1,exp:"Donald Ferguson es el asistente principal de Cecil Stedman y uno de sus colaboradores más leales.",extra:"La lealtad de Donald hacia Cecil es incondicional, lo que lo pone en situaciones moralmente cuestionables."},
  {t:"m",q:"¿Cómo evoluciona el Teen Team a lo largo de la historia de Invincible?",o:["Se mantienen exactamente igual durante toda la serie","Evolucionan, se dividen, algunos se vuelven antagonistas y el grupo cambia fundamentalmente","Todos mueren al final del primer arco","Se fusionan permanentemente con los Guardianes del Globo"],a:1,exp:"El Teen Team evoluciona enormemente a lo largo de la serie con cambios de membresía, alianzas rotas y giros importantes.",extra:"Robot en particular tiene uno de los cambios más dramáticos, pasando de héroe a antagonista."},
  {t:"m",q:"¿Qué hace que la pelea de Mark contra Conquest sea especialmente significativa narrativamente?",o:["Es la primera vez que Mark pelea en el espacio","Es la primera batalla que Mark casi pierde completamente y donde Atom Eve interviene","Es la batalla que revela la debilidad sonora de los Viltrumitas","Es la primera vez que Thragg aparece directamente"],a:1,exp:"La pelea con Conquest es significativa porque Mark casi muere y la intervención de Eve define su relación romántica.",extra:"La pelea marca un punto de inflexión tanto en el poder de Mark como en su relación con Eve."},
  {t:"m",q:"¿Qué simboliza Terra Grayson para el final de la serie de Invincible?",o:["Terra no aparece en el cómic original","Terra representa el futuro y la esperanza del legado de Mark más allá de su tiempo","Terra es quien finalmente derrota a Thragg","Terra se convierte en la nueva Invincible tras la muerte de Mark"],a:1,exp:"Terra representa el legado futuro de Mark y la continuación de los valores que él defendió durante toda su vida.",extra:"Su existencia proyecta la historia hacia el futuro y da esperanza de que el sacrificio de Mark tuvo significado."},
  {t:"m",q:"¿Cuál es la principal herramienta que usa Cecil para controlar a los superhéroes de la Tierra?",o:["Implantes de control mental","Información y recursos que los héroes necesitan","Amenazas directas a sus familias","Tecnología que suprime sus poderes temporalmente"],a:1,exp:"Cecil controla a los superhéroes proveyéndoles información, recursos y apoyo que los hace dependientes de la GDA.",extra:"Esta dependencia le da a Cecil una enorme influencia sobre los héroes sin necesitar métodos directamente coercitivos."},
  {t:"m",q:"¿Por qué se dice que Invincible tuvo un final satisfactorio para la mayoría de los fans?",o:["Porque dejó todo abierto para una secuela","Porque Kirkman planeó el final desde el principio y resolvió todos los arcos principales","Porque todos los personajes mueren heroicamente","Porque Mark pierde todos sus poderes y se convierte en humano"],a:1,exp:"Kirkman planificó el final de Invincible y lo ejecutó resolviendo los principales arcos de la historia.",extra:"Un final planificado es inusual en los cómics de superhéroes, lo que hizo que el de Invincible fuera muy elogiado."},
  {t:"m",q:"¿Qué aspecto de Invincible lo hace más relatable que personajes como Superman?",o:["Mark tiene los mismos poderes exactos que Superman","Mark es un adolescente normal que debe equilibrar la escuela, la familia y ser superhéroe","Mark nunca tiene problemas de identidad secreta","Mark vive en Metrópolis igual que Superman"],a:1,exp:"Mark es un adolescente tratando de equilibrar la vida normal en la escuela con las responsabilidades de ser superhéroe.",extra:"Esta perspectiva adolescente y sus problemas cotidianos lo hacen más accesible que la figura perfecta de Superman."},
  {t:"m",q:"¿Qué significa en términos narrativos que Invincible sea una deconstrucción del género de superhéroes?",o:["Que destruye los cómics de superhéroes existentes","Que examina y subvierte las convenciones del género mostrando sus implicaciones reales","Que reconstruye personajes clásicos con diseños nuevos","Que es una parodia cómica del género"],a:1,exp:"Deconstruir el género significa examinar sus convenciones y mostrar qué pasaría realmente si esas situaciones ocurrieran.",extra:"Kirkman usa la estructura del cómic de superhéroes para explorar temas más oscuros y consecuencias reales."},
  {t:"m",q:"¿Qué hace especial a Allen el Alienígena como personaje entre los aliados de Mark?",o:["Su poder extremo que supera a todos","Su personalidad amigable, su humor y su dedicación genuina a su misión","Su capacidad de engañar a los Viltrumitas","Su historia de amor con Eve"],a:1,exp:"Allen combina una personalidad genuinamente amigable con humor natural y una dedicación sincera a su trabajo.",extra:"Su amistad con Mark es una de las más cálidas de la serie a pesar de las diferencias entre los dos."},
  {t:"m",q:"¿Cuándo Mark le dice la verdad a Amber sobre ser Invincible?",o:["Nunca se lo dice, Amber lo descubre sola","Se lo dice en su primera cita","Se lo dice después de que su relación ya lleva un tiempo y Amber está decepcionada","Se lo dice en el momento en que conoce sus poderes"],a:2,exp:"Mark le revela su identidad a Amber después de que su relación lleva tiempo, y Amber ya está frustrada por sus ausencias.",extra:"La revelación tardía daña la relación porque Amber siente que Mark no confiaba en ella."},
  {t:"m",q:"¿Cuál es el título que ostenta Thragg dentro del Imperio Viltrumita?",o:["Almirante Supremo","Gran Regente","Comandante de la Flota","Primer Viltrumita"],a:1,exp:"Thragg es el Gran Regente del Imperio Viltrumita, el rango más alto dentro de su jerarquía militar.",extra:"Su posición lo convierte en el responsable de las operaciones de conquista galácticas."},
  {t:"m",q:"¿Qué calidad distingue a Thragg de otros Viltrumitas en términos de poder?",o:["Es el único Viltrumita que puede volar","Es considerado el Viltrumita más poderoso en existencia","Es el único que puede resistir la frecuencia sonora","Puede regenerarse completamente de cualquier herida"],a:1,exp:"Thragg es reconocido como el Viltrumita más poderoso de todos, superando incluso a Nolan en combate puro.",extra:"Su nivel de poder lo convierte en una amenaza existencial para cualquiera que se le oponga."},
  {t:"m",q:"¿Qué hace que la escena de Anissa con Mark sea tan polémica en el cómic?",o:["Porque Anissa mata a varios civiles durante el encuentro","Porque la naturaleza no consensual del encuentro lo convierte en un momento oscuro y controvertido","Porque Anissa traiciona al Imperio durante la escena","Porque Mark revela su identidad a Anissa innecesariamente"],a:1,exp:"La escena es polémica por su naturaleza no consensual, representando uno de los momentos más oscuros del cómic.",extra:"Kirkman ha reconocido que esta escena es deliberadamente incómoda para mostrar la brutalidad del Imperio Viltrumita."},
  {t:"m",q:"¿Por qué los Viltrumitas necesitan reproducirse con otras razas según la historia?",o:["Para crear guerreros más versátiles","Sufrieron una plaga que diezmó su población y necesitan reproducirse con otras razas","Es parte de su ritual cultural ancestral","Para conquistar más rápido sin necesidad de ejércitos"],a:1,exp:"Los Viltrumitas sufrieron una plaga que redujo drásticamente su población y por eso buscan reproducirse con otras razas.",extra:"Esta necesidad biológica es la razón real detrás de la misión de Anissa con Mark."},
  {t:"m",q:"¿Qué hace que la colaboración Kirkman-Ottley sea tan especial para el cómic de Invincible?",o:["Ottley también escribía algunos issues junto a Kirkman","La consistencia visual de Ottley durante años creó una identidad visual única para la serie","Ottley diseñó todos los villanos y Kirkman todos los héroes","Ambos publicaron el cómic sin intervención de Image Comics"],a:1,exp:"La consistencia visual de Ryan Ottley durante años como dibujante principal creó una identidad visual única e inconfundible para la serie.",extra:"Pocos cómics de larga duración mantienen el mismo dibujante durante tanto tiempo, lo que beneficia la cohesión visual."},
  {t:"m",q:"¿Qué aspecto de la guerra Viltrumita la convierte en un arco épico de la serie?",o:["Ocurre completamente fuera de la Tierra sin afectar a los personajes conocidos","Eleva el conflicto a escala galáctica involucrando planetas, razas y el destino del universo","Solo involucra a Mark y a Thragg en un duelo personal","Dura solo dos números y se resuelve rápidamente"],a:1,exp:"La Guerra Viltrumita eleva el conflicto a escala galáctica involucrando planetas, razas alienígenas y el destino de la libertad universal.",extra:"Esto transforma a Mark de héroe local a figura de importancia cósmica en el universo de la serie."},
  {t:"m",q:"¿Qué habilidad especial tiene Dupli-Kate además de crear copias de sí misma?",o:["Puede fusionar sus copias para aumentar su fuerza","Cada copia comparte sus sentidos con las demás simultáneamente","Sus copias pueden existir indefinidamente incluso sin ella","Puede transferir recuerdos entre sus copias"],a:1,exp:"Las copias de Dupli-Kate comparten su conciencia y sentidos, permitiéndole coordinar perfectamente muchas copias.",extra:"Esto la hace extremadamente valiosa en misiones de reconocimiento y combate simultáneo en múltiples frentes."},
  {t:"m",q:"¿Cuál es el legado que deja la serie de Invincible para los cómics de imagen?",o:["Demostró que los cómics independientes no pueden competir con Marvel y DC","Demostró que Image podía publicar obras de calidad sostenida durante décadas","Fue el único cómic exitoso de Image Comics en su historia","Transformó Image en una editorial de terror exclusivamente"],a:1,exp:"Invincible demostró que Image Comics podía publicar obras superheroicas de calidad sostenida durante décadas.",extra:"Junto a The Walking Dead estableció a Image como una editorial capaz de crear auténticas sagas superheroicas."},
  {t:"m",q:"¿Qué diferencia a Invincible de The Boys como deconstrucción del género de superhéroes?",o:["Invincible es menos violenta que The Boys","Invincible tiene un protagonista genuinamente heroico a diferencia del cinismo total de The Boys","Invincible no tiene crítica social mientras The Boys sí","Invincible es una comedia y The Boys un drama"],a:1,exp:"A diferencia de The Boys, Invincible tiene un protagonista genuinamente heroico que cree en el bien, sin cinismo total.",extra:"Esto hace que Invincible sea una deconstrucción que también celebra los valores del género en lugar de solo destruirlos."},
  {t:"m",q:"¿Cuál es la razón por la que la brutal pelea del episodio 8 tomó desprevenidos a los espectadores nuevos?",o:["Porque fue la primera vez que apareció violencia en la serie","Porque el tono de los primeros episodios era deliberadamente más ligero haciendo el contraste más impactante","Porque la violencia estaba completamente editada en los primeros episodios","Porque la serie prometió explícitamente no tener violencia hasta ese punto"],a:1,exp:"Los primeros episodios tenían un tono superheroico más estándar que hacía el giro brutal del episodio 8 más impactante.",extra:"Esta estrategia narrativa es la misma que usa el cómic original, construyendo expectativas para romperlas."},
  {t:"m",q:"¿Qué logra hacer Mark en la historia que ningún otro Viltrumita había conseguido plenamente?",o:["Vencer a Thragg en combate singular","Derrotar a un ejército Viltrumita entero él solo","Encontrar un verdadero equilibrio entre sus valores humanos y su herencia Viltrumita","Crear tecnología que neutraliza los poderes Viltrumitas"],a:2,exp:"Mark logra encontrar un equilibrio genuino entre su herencia Viltrumita y sus valores humanos, creando su propia identidad.",extra:"Esto lo convierte en un nuevo tipo de Viltrumita que los del Imperio no pueden comprender completamente."},
  {t:"m",q:"¿Qué impacto emocional más duradero tiene Nolan en Debbie?",o:["Debbie lo olvida rápidamente y sigue adelante sin secuelas","Debbie sufre una profunda crisis de identidad al descubrir que su vida entera fue construida sobre mentiras","Debbie se convierte en activista contra los Viltrumitas","Debbie abandona a Mark también al asociarlo con Nolan"],a:1,exp:"Debbie sufre una crisis de identidad devastadora al descubrir que su vida, sus recuerdos y su amor fueron construidos sobre mentiras.",extra:"Su proceso de recuperación y crecimiento personal es uno de los arcos más emotivos y realistas de la serie."},
  {t:"m",q:"¿Qué papel tiene la herencia humana de Mark en su combate contra los Viltrumitas?",o:["Su herencia humana es una debilidad que los Viltrumitas explotan","Su empatía humana y sus valores le dan una fortaleza mental que los Viltrumitas no comprenden","La herencia humana no tiene ningún papel en los combates","Su herencia humana le da poderes adicionales que los Viltrumitas puros no tienen"],a:1,exp:"La empatía y los valores humanos de Mark le dan una fortaleza psicológica que los Viltrumitas puramente militaristas no entienden.",extra:"Esto es lo que permite a Mark resistir la presión del Imperio de convertirse en conquistador."},
  {t:"m",q:"¿Por qué la serie de Invincible fue renovada por múltiples temporadas tan rápidamente?",o:["Por obligaciones contractuales previas al estreno","Por su éxito masivo de audiencia y crítica desde la primera temporada","Porque era una coproducción con el estudio de Kirkman","Por ser la serie más barata de producir en Amazon Prime"],a:1,exp:"El éxito masivo de audiencia y la aclamación crítica de la primera temporada llevaron a Amazon a renovar rápidamente.",extra:"La serie se convirtió en uno de los grandes éxitos de Amazon Prime Video en su estreno."},
  {t:"m",q:"¿Qué poderes heredará Terra Grayson de sus padres según lo que se muestra en el cómic?",o:["Solo los poderes Viltrumitas de su padre","Solo la manipulación de materia de su madre Eve","Poderes combinados de su padre Viltrumita y la manipulación de materia de Eve","Poderes completamente nuevos sin relación con los de sus padres"],a:2,exp:"Terra hereda tanto los poderes Viltrumitas de Mark como la capacidad de manipulación de materia de Eve.",extra:"Esta combinación la convierte en una de las figuras más poderosas del futuro del universo de Invincible."},
  {t:"m",q:"¿Cómo trata Invincible el tema del trauma psicológico en los superhéroes?",o:["Lo ignora completamente como la mayoría de los cómics del género","Lo muestra explícitamente como una consecuencia real de las batallas y traiciones vividas","Solo muestra trauma en los villanos, no en los héroes","El trauma se resuelve siempre en el mismo número en que aparece"],a:1,exp:"Invincible muestra explícitamente las consecuencias psicológicas del trauma en personajes como Mark, Debbie y otros.",extra:"Este tratamiento realista del trauma emocional es uno de los elementos que distingue a la serie."},
  {t:"m",q:"¿Cuál fue el primer gran arco de Invincible que demostró el alcance cósmico de la serie?",o:["El arco de los Mellizos Mauler","El arco de la invasión de los Sequids en Marte","La revelación de Omni-Man y sus consecuencias interestelares","El arco del primer enfrentamiento con Conquest"],a:2,exp:"La revelación de Omni-Man y sus consecuencias interestelares fue el primer arco que mostró el alcance cósmico de la serie.",extra:"Esto estableció que Invincible no sería solo un cómic de superhéroes terrestres sino una historia de alcance galáctico."},
  {t:"m",q:"¿Qué hace que la relación de Mark con Allen el Alienígena sea importante para la narrativa?",o:["Allen entrena a Mark para controlar sus poderes","Allen conecta a Mark con el universo más amplio y con la lucha contra el Imperio Viltrumita","Allen es el amor interés romántico de Mark en el espacio","Allen es el único que conoce la verdad sobre Cecil Stedman"],a:1,exp:"Allen conecta a Mark con el universo más amplio y le proporciona perspectiva sobre la amenaza del Imperio Viltrumita.",extra:"Sin Allen, Mark solo tendría la perspectiva terrestre y no comprendería la escala real del conflicto Viltrumita."},
  {t:"m",q:"¿En qué aspecto Robot evoluciona de forma más sorprendente a lo largo de la serie?",o:["Pasa de ser un genio tímido a un combatiente brutal","Evoluciona de héroe leal a antagonista que cree que solo él puede salvar a la humanidad","Pasa de controlar un robot a tener un cuerpo humano completo","Evoluciona de villano a héroe sin ningún giro inesperado"],a:1,exp:"Robot evoluciona hasta convertirse en un antagonista que cree que solo él puede salvar a la humanidad con sus métodos autoritarios.",extra:"Este giro de personaje es uno de los más sorprendentes de la serie dado su rol inicial como héroe del Teen Team."},
  {t:"m",q:"¿Cuál es el papel de Mark Grayson en la historia de la humanidad al final del cómic?",o:["Es solo un superhéroe local sin importancia galáctica","Se convierte en una figura central en la relación entre la Tierra y el resto del universo","Muere heroicamente sin ver el futuro que construyó","Abandona la Tierra para vivir permanentemente en el espacio"],a:1,exp:"Mark se convierte en una figura central en la relación entre la Tierra y el resto del universo, siendo puente entre ambos mundos.",extra:"Su papel único como Viltrumita criado con valores humanos lo hace el candidato ideal para esta función."},
  {t:"m",q:"¿Quién es Angstrom Levy y qué poderes lo hacen una amenaza única para Invincible?",o:["Un villano que puede viajar entre dimensiones paralelas y combinar conocimiento de múltiples universos","Un Viltrumita renegado con fuerza superior a la de Omni-Man","Un científico que crea supervillanos con tecnología","Un clone de Cecil Stedman con acceso a todas las bases de la GDA"],a:0,exp:"Angstrom Levy puede crear portales a dimensiones paralelas, lo que lo hace extremadamente difícil de detener y le da acceso a conocimiento de múltiples versiones del universo.",extra:"Levy culpa a Invincible de su desfiguración durante un accidente en su ritual de absorción de conocimiento multiversal. Se convierte en uno de los enemigos más personales de Mark."},
  {t:"m",q:"¿Qué son los Reanimen y quién los crea en el universo de Invincible?",o:["Cyborgs cadavéricos creados por D.A. Sinclair para la GDA","Robots de combate diseñados por Robot","Clones de Viltrumitas muertos","Zombies controlados por los Sequids"],a:0,exp:"Los Reanimen son cadáveres humanos convertidos en cyborgs de combate por D.A. Sinclair, un científico sin escrúpulos que trabaja secretamente para Cecil Stedman y la GDA.",extra:"La existencia de los Reanimen es uno de los primeros indicios del lado oscuro de Cecil: usa métodos cuestionables justificados por resultados. Mark queda horrorizado cuando descubre la verdad."},
  {t:"m",q:"¿Qué son los Flaxans y cuál es su peculiaridad más notable al invadir la Tierra?",o:["Alienígenas que envejecen rápidamente cuando están en la dimensión de la Tierra, muriendo en minutos","Aliens de agua que no pueden sobrevivir en atmósferas secas","Robots enviados por el Imperio Viltrumita para explorar","Parasítos que controlan la mente de sus huéspedes humanos"],a:0,exp:"Los Flaxans son alienígenas cuya biología hace que envejezcan drásticamente al entrar en la dimensión de la Tierra: lo que son minutos para ellos equivalen a años de envejecimiento.",extra:"Sus invasiones iniciales fracasan precisamente por este motivo. Eventualmente desarrollan tecnología para compensar el efecto, pero siempre han representado una amenaza intermitente y creativa en la narrativa."},
  {t:"m",q:"¿Cuál es la debilidad física de los Viltrumitas que los hace vulnerables pese a su poder extremo?",o:["Frecuencias sonoras específicas (sonic vibrations) que destruyen sus oídos internos","La luz ultravioleta intensa","El contacto con agua salada","Una raza de bacterias terrestres"],a:0,exp:"Los Viltrumitas tienen oídos internos extremadamente sensibles. Ciertas frecuencias sonoras específicas pueden debilitarlos, causarles dolor extremo o incluso matarlos.",extra:"Esta debilidad es crucial en la narrativa porque permite que seres mucho menos poderosos representen una amenaza real contra los prácticamente invulnerables Viltrumitas."},
  {t:"m",q:"¿Qué descubre Mark sobre su hermano menor Oliver (hijo de Nolan con una mujer alien) que lo hace diferente a los Viltrumitas puros?",o:["Oliver envejece mucho más rápido que un Viltrumita puro debido a la mezcla de razas","Oliver no puede volar como los Viltrumitas normales","Oliver carece de superfuerza completamente","Oliver necesita alimentarse de energía solar para mantener sus poderes"],a:0,exp:"Oliver, al ser mestizo (Viltrumita y raza alienígena de corta vida), envejece mucho más rápido que Mark, lo que crea una dinámica fraternal inusual donde Oliver crece de bebé a adolescente en meses.",extra:"Esta característica hace que la relación entre Mark y Oliver sea única: Mark experimenta la crianza de un hermano que crece aceleradamente y adopta una visión del mundo más pragmática y violenta."},
  {t:"m",q:"¿Cómo termina la primera batalla de Invincible contra Conquest y cuál es su importancia en la serie?",o:["Invincible pierde casi hasta la muerte y Conquest lo deja por muerto creyendo que ha ganado","Invincible mata a Conquest fácilmente en su primer encuentro","Conquest y Mark llegan a un acuerdo de no agresión","El combate termina en empate cuando llega Omni-Man"],a:0,exp:"En su primer encuentro, Conquest casi mata a Mark. La brutal batalla muestra que Mark aún no está a la altura de los mejores Viltrumitas, siendo una de las peleas más violentas y oscuras del cómic.",extra:"La batalla tiene consecuencias duraderas: Mark queda gravemente herido y Atom Eve pierde su bebé durante el caos del combate. Este evento es considerado uno de los más impactantes de toda la serie."},
  {t:"m",q:"¿Qué hace que Battle Beast sea un antagonista memorable en Invincible más allá de su fuerza bruta?",o:["Su filosofía: solo busca una pelea digna de él, sin lealtad a ningún lado","Es el único ser que puede igualar en poder a un Viltrumita puro","Tiene poderes mentales que complementan su fuerza física","Es el padre biológico de un personaje principal no revelado hasta el final"],a:0,exp:"Battle Beast solo busca combates que le supongan un desafío real. No tiene lealtades permanentes y puede cambiar de bando si eso le garantiza peleas más emocionantes.",extra:"En una escena icónica, Battle Beast derrota solo y consecutivamente a casi todos los Guardianes del Globo en una sola noche. Más adelante, decide ir a luchar contra los propios Viltrumitas por el desafío."},
  {t:"m",q:"¿Cómo consiguió Black Samson sus poderes en el universo de Invincible?",o:["Obtuvo sus poderes mediante un traje tecnológico que le fue retirado y luego reintegrado de forma permanente","Los heredó genéticamente de su padre alienígena","Los recibió de Cecil Stedman como parte de un experimento","Son poderes naturales con los que nació, similares a los de Mark"],a:0,exp:"Black Samson obtuvo sus poderes a través de un traje que potenciaba sus habilidades, pero ese traje le fue retirado. Más adelante recuperó sus poderes de forma permanente.",extra:"Este arco de Black Samson ilustra el tema recurrente de Invincible sobre la identidad y el origen de los poderes: ¿son realmente tuyos si dependen de tecnología externa?"},
  {t:"m",q:"¿Cuál es la verdadera historia de origen de Atom Eve (Samantha Eve Wilkins)?",o:["Fue creada como experimento gubernamental con poderes de manipulación de la materia","Es una Viltrumita enviada para vigilar a Mark sin su conocimiento","Sus poderes surgieron espontáneamente durante una enfermedad infantil","Es la hija de un científico que la expuso a radiación"],a:0,exp:"Atom Eve fue creada por un científico del gobierno como experimento: una niña diseñada para tener poderes de manipulación de la materia. Fue dada en adopción a una familia civil para ocultar su origen.",extra:"Este secreto sobre su origen es relevante porque explica por qué sus poderes son tan únicos y amplios. Eve puede manipular la materia a nivel atómico, haciéndola potencialmente la persona más poderosa de la Tierra."},
  {t:"m",q:"¿Qué duración tuvo la serie de cómic Invincible de Robert Kirkman?",o:["2003 a 2018, con 144 números y 3 especiales","1998 a 2010, con 100 números","2005 a 2020, con 200 números","2000 a 2015, con 120 números"],a:0,exp:"Invincible se publicó desde 2003 hasta 2018, completando 144 números más algunos especiales y crossovers, con Robert Kirkman como escritor durante toda su duración.",extra:"La serie terminó con una conclusión planificada, no cancelación, algo inusual en el mundo de los cómics independientes. Kirkman decidió terminarla cuando tenía la historia completa que quería contar."},
  {t:"m",q:"¿Qué actor presta voz a Omni-Man en la serie animada de Amazon Prime y cómo fue recibida su actuación?",o:["J.K. Simmons, con una actuación ampliamente elogiada que captura la complejidad del personaje","Liam Neeson, con un tono más frío y calculador","Bryan Cranston, quien aporta ambigüedad moral al papel","Tom Hanks, eligiendo deliberadamente contra su imagen habitual"],a:0,exp:"J.K. Simmons da voz a Omni-Man con una actuación que captura perfectamente tanto la autoridad y amabilidad del padre como la brutalidad del agente Viltrumita.",extra:"J.K. Simmons es conocido por sus papeles de personajes de autoridad como el Sargento Hartman (Full Metal Jacket) y J. Jonah Jameson (Spider-Man). Su voz grave y versátil fue considerada perfecta para el rol."},
  {t:"m",q:"¿Qué actor de voz interpreta a Mark Grayson / Invincible en la serie animada de Amazon?",o:["Steven Yeun","Steven Carell","John Cho","Simu Liu"],a:0,exp:"Steven Yeun, conocido por su papel de Glenn en The Walking Dead, interpreta a Mark Grayson en la serie animada de Invincible.",extra:"La elección de Yeun fue considerada perfecta: su voz transmite la juventud, el idealismo y la vulnerabilidad de Mark. The Walking Dead fue también creada por Robert Kirkman, creando una conexión entre actor y creador."},
  {t:"m",q:"¿Cómo se estructura la primera temporada de la serie animada de Invincible en relación al cómic?",o:["Adapta aproximadamente los primeros 13 números del cómic con algunas modificaciones","Sigue exactamente el cómic sin ningún cambio","Solo adapta el primer arco (el reveal de Omni-Man) en 8 episodios","Mezcla arcos de diferentes etapas del cómic sin seguir su orden"],a:0,exp:"La primera temporada adapta aproximadamente los primeros 13 números del cómic original, con algunas modificaciones narrativas y adiciones para el formato televisivo.",extra:"Notable cambio: la serie expande la perspectiva más allá de Mark, mostrando los planes de Cecil y otras tramas en paralelo que el cómic presentaba de forma más lineal."},
  {t:"m",q:"¿Qué ocurre con Rex Splode en el arco de la Viltrumite War y cómo impacta a los demás personajes?",o:["Muere heroicamente sacrificándose para proteger a Eve y a la Tierra durante la invasión","Traiciona a los Guardianes y se une temporalmente a los Viltrumitas","Se retira después de perder sus poderes en combate","Sobrevive y se convierte en el nuevo líder de los Guardianes"],a:0,exp:"Rex Splode muere heroicamente durante la invasión Viltrumita, sacrificando su vida. Su muerte impacta profundamente a Eve y redefine la relación de esta con Mark.",extra:"La muerte de Rex es significativa porque elimina el triángulo amoroso Mark-Eve-Rex de forma permanente y permite que la relación de Mark y Eve evolucione sin esa tensión. Es uno de los momentos más emotivos de la serie."},
  {t:"m",q:"¿Qué es la Coalición de Planetas y cuál es su objetivo en el universo de Invincible?",o:["Una alianza intergaláctica creada para resistir la expansión del Imperio Viltrumita","El gobierno galáctico que controla el comercio entre estrellas","Una organización de científicos que estudian razas alienígenas","El grupo que enviaron al padre de Mark a la Tierra originalmente"],a:0,exp:"La Coalición de Planetas es una alianza de múltiples razas alienígenas cuyo objetivo principal es resistir y eventualmente detener la expansión del Imperio Viltrumita.",extra:"Allen el Alienígena es el representante de la Coalición que más interactúa con Mark. La existencia de la Coalición establece que el conflicto con los Viltrumitas es de escala galáctica, no solo terrestre."},
  {t:"m",q:"¿Qué hace Anissa en uno de los momentos más oscuros y polémicos del cómic de Invincible?",o:["Fuerza sexualmente a Mark cuando él se niega a cooperar con el plan Viltrumita de reproducción","Le roba los poderes a Mark temporalmente en combate","Lo engaña para que mate a un inocente creyendo que es un criminal","Lo captura y lo entrega al Gran Regente Thragg como prisionero"],a:0,exp:"Anissa fuerza sexualmente a Mark, enviada por el Imperio Viltrumita para reproducirse con él como parte de su plan de repoblación. Es uno de los momentos más oscuros y cuestionados del cómic.",extra:"La escena generó debate en el fandom sobre su inclusión. Kirkman la defendió como parte del retrato sin filtros de la naturaleza del Imperio Viltrumita y sus valores completamente ajenos a los humanos."},
  {t:"m",q:"¿Cómo termina la relación entre Nolan Grayson y la humanidad a lo largo de la serie de Invincible?",o:["Nolan vuelve a la Tierra convertido en aliado y hace las paces con su hijo Mark antes de morir","Nolan permanece enemigo de la humanidad hasta el final","Nolan nunca regresa después de huir en el número 11","Nolan termina destruyendo la Tierra para cumplir su misión Viltrumita original"],a:0,exp:"Nolan regresa a la Tierra transformado, se reconcilia con Mark y se convierte en aliado de la humanidad, muriendo eventualmente como resultado de sus elecciones.",extra:"El arco de Nolan es en muchos sentidos el más completo de la serie: de agente imperial a fugitivo, a prisionero, a aliado y padre redimido. Su relación con Mark es el corazón emocional de toda la narrativa."},
  {t:"m",q:"¿Qué papel juega Monster Girl en los Guardianes del Globo y cuál es el secreto de su envejecimiento?",o:["Es la miembro más experimentada a pesar de su apariencia infantil, ya que rejuvenece con cada transformación","Es la más joven y la que menos experiencia tiene del grupo","Es un androide diseñado para parecer una niña","Es la hija de un Viltrumita que heredó sus poderes al nacer"],a:0,exp:"Monster Girl es en realidad mucho mayor de lo que parece: cada vez que se transforma en monstruo, su cuerpo rejuvenece al volver a su forma humana, haciéndola regresar a la apariencia de una niña.",extra:"Este mecanismo inverso de envejecimiento la convierte en un personaje con siglos de experiencia atrapada en un cuerpo que retrocede en edad. Su verdadera personalidad y sabiduría contrastan dramáticamente con su apariencia."},
  {t:"m",q:"¿Cómo describe Robert Kirkman el proceso de creación del final de Invincible?",o:["Lo tenía planificado desde los primeros números y fue ejecutando la historia hacia ese destino","Lo improvisó completamente en las últimas décadas de números","Lo decidió en el número 100 y cambió toda la dirección de la serie","El final fue determinado por los lectores a través de votaciones en redes sociales"],a:0,exp:"Kirkman ha declarado que tenía el final de Invincible planificado desde el principio, y que toda la serie fue construida para llegar a ese punto de destino.",extra:"Esta planificación a largo plazo es inusual en los cómics independientes y explica por qué la serie tiene una coherencia narrativa notable. Kirkman aplicó un enfoque similar al final de The Walking Dead."},
  {t:"m",q:"¿Cuál es el nombre del hijo de Mark Grayson y Atom Eve que aparece en la serie?",o:["Marky (Marcus) Grayson","Oliver Grayson","Nolan Grayson Jr.","Zane Grayson"],a:0,exp:"Mark y Eve tienen un hijo llamado Marky (Marcus) Grayson, que hereda poderes de ambos padres.",extra:"La paternidad de Mark representa un punto de madurez en la narrativa: el personaje que comenzó como un adolescente descubriendo sus poderes llega a ser padre, cerrando el ciclo de la serie."},
  {t:"m",q:"¿Qué diferencia fundamentalmente a Invincible de la mayoría de los cómics de superhéroes convencionales?",o:["Sus consecuencias permanentes y ultraviolencia sin censura que afectan a los personajes de forma duradera","Que los superhéroes no tienen trajes ni identidades secretas","Que todos los arcos duran exactamente 6 números como un trade paperback","Que el protagonista es el único superhumano existente en el mundo"],a:0,exp:"Invincible es conocido por sus consecuencias permanentes: los personajes mueren definitivamente, sufren traumas duraderos y las heridas físicas importan. La violencia es gráfica y tiene peso real.",extra:"Esta filosofía narrativa contrasta con el 'status quo' de los grandes editoriales donde los personajes rara vez cambian permanentemente. En Invincible, las decisiones tienen consecuencias irreversibles."},
  {t:"m",q:"¿Qué tipo de relación tiene el cómic de Invincible con el universo de The Walking Dead de Kirkman?",o:["Son universos ficticios separados, aunque comparten editorial (Image Comics) y algunas referencias cruzadas","Son el mismo universo en diferentes épocas","Walking Dead ocurre después del apocalipsis de Invincible","Son totalmente independientes sin ninguna conexión"],a:0,exp:"Invincible y The Walking Dead son universos separados, pero comparten editorial Image Comics y tienen algunos crossovers no canónicos. En los cómics de Invincible hay referencias a The Walking Dead.",extra:"Kirkman ha confirmado que los dos universos no están conectados canónicamente, aunque en una portada de crossover cómico, Rick Grimes y Mark Grayson se encuentran. Ambas series se publicaron en Image simultáneamente durante años."},
  {t:"m",q:"¿Qué hace que la pelea entre Invincible y Omni-Man en el issue #11 sea considerada revolucionaria en el cómic de superhéroes?",o:["Es explícitamente brutal, con daños físicos reales en los personajes, y dura varios números sin resolución rápida","El diálogo entre padre e hijo mientras pelean sin violencia real","La escala cósmica que involucra planetas destruidos","Que ambos personajes usan poderes nunca antes vistos en el género"],a:0,exp:"La pelea es revolucionaria por su brutalidad explícita y sus consecuencias: Nolan casi mata a Mark repetidamente, destruye partes de la ciudad y daña a civiles, todo mientras trata de convencer a su hijo de unirse al Imperio.",extra:"El issue #11 se convirtió en un hito del cómic de superhéroes por subvertir radicalmente las expectativas del género. La violencia tiene peso real y el cliffhanger deja al lector sin certeza sobre si Mark sobrevivirá."},
  {t:"m",q:"¿Cuántas temporadas tiene la serie animada de Invincible en Amazon Prime Video hasta 2024?",o:["Dos temporadas con una tercera confirmada","Una temporada completa","Tres temporadas completas","Dos temporadas pero fue cancelada"],a:0,exp:"La serie animada de Invincible tiene dos temporadas completas y una tercera confirmada. La segunda temporada se dividió en dos partes (2023 y 2024).",extra:"La segunda temporada fue especialmente esperada por el largo período de espera desde la primera (2021). Fue bien recibida y confirmó el éxito continuo de la serie."},
  {t:"m",q:"¿Qué editorial publica el cómic de Invincible y qué importancia tiene esa editorial en el mundo del cómic?",o:["Image Comics, fundada por artistas que se independizaron de Marvel en 1992 por derechos creativos","Dark Horse Comics, especializada en cómics de ciencia ficción","IDW Publishing, conocida por sus licencias de propiedades pop","BOOM! Studios, editorial independiente fundada en 2005"],a:0,exp:"Invincible se publica por Image Comics, fundada en 1992 por Todd McFarlane, Jim Lee, Rob Liefeld y otros artistas estrella que dejaron Marvel para tener control creativo sobre sus personajes.",extra:"Image Comics es famosa por permitir que los creadores retengan los derechos de sus personajes. Spawn de Todd McFarlane y Saga de Brian K. Vaughan son otras series icónicas publicadas allí."},
  {t:"m",q:"¿Qué personaje de Invincible es conocido por su capacidad de manipular objetos a nivel subatómico y su potencial prácticamente ilimitado?",o:["Atom Eve (Samantha Eve Wilkins)","El Reverso","Shrinking Ray","D.A. Sinclair con nanobots"],a:0,exp:"Atom Eve puede manipular la materia a nivel atómico, convirtiendo cualquier material en otro. Teóricamente podría crear cualquier cosa o destruir cualquier objeto a nivel molecular.",extra:"Su limitación principal no es física sino psicológica: Eve necesita entender a nivel intuitivo qué está transformando. Esto la hace extremadamente poderosa pero no omnipotente, manteniendo la tensión narrativa."},
  {t:"m",q:"¿Cuál es el verdadero nombre del villano Robot antes de revelarse que no es un androide?",o:["Rudy Conners","Cecil Rourke","Roger Stelfreze","James Sinclair"],a:0,exp:"Robot es en realidad Rudy Conners, un genio con un cuerpo deformado que construyó el robot para poder actuar en el mundo exterior. Más adelante se crea un cuerpo humano clonado.",extra:"El reveal de la verdadera identidad de Robot es uno de los más impactantes de la serie. Rudy luego evoluciona hasta convertirse en un antagonista autoritario que cree que la humanidad necesita ser controlada para sobrevivir."},
  {t:"m",q:"¿Cómo se diferencia la representación de los superhéroes en Invincible respecto a los universos de Marvel y DC?",o:["En Invincible los superhéroes son empleados pagados por el gobierno y la GDA controla sus actividades","Los superhéroes de Invincible tienen poderes mágicos exclusivamente","En Invincible no existen identidades secretas","Los superhéroes de Invincible no pueden morir permanentemente"],a:0,exp:"En Invincible, la GDA (Global Defense Agency) opera como una agencia gubernamental que coordina y emplea a los superhéroes, a diferencia de los equipos voluntarios de Marvel y DC.",extra:"Cecil Stedman, director de la GDA, representa el punto de vista pragmático del gobierno: los superhéroes son recursos que deben ser administrados, no agentes independientes."},
  {t:"m",q:"¿Qué ocurre con Nolan Grayson cuando es capturado por la Coalición de Planetas tras huir de la Tierra?",o:["Es juzgado y encarcelado, pero eventualmente se convierte en un aliado valioso de la Coalición","Es ejecutado inmediatamente como criminal de guerra Viltrumita","Es liberado de inmediato al revelar información sobre el Imperio","Es sometido a lavado de cerebro para convertirlo en agente de la Coalición"],a:0,exp:"Nolan es capturado, juzgado por sus crímenes y encarcelado. Pero su conocimiento del Imperio Viltrumita lo convierte en un activo valioso, y eventualmente trabaja con la Coalición.",extra:"Este arco muestra la transformación de Nolan de agente imperial a figura compleja: ni héroe ni villano definitivo, sino un personaje que debe enfrentarse a las consecuencias de toda una vida de imperialismo galáctico."},
  {t:"m",q:"¿Qué significa para Mark descubrir la verdad sobre su padre Omni-Man en términos de su identidad como superhéroe?",o:["Destruye temporalmente su fe en los ideales de bondad y protección que motivaban sus acciones","Lo hace más fuerte inmediatamente y sin consecuencias psicológicas","Le revela que siempre supo la verdad inconscientemente","No tiene impacto real porque Mark ya desconfiaba de su padre"],a:0,exp:"La revelación destruye temporalmente los cimientos de la identidad heroica de Mark: ¿puede ser un héroe genuino si su legado es el de un conquistador imperial?",extra:"Este conflicto de identidad es el corazón emocional de los primeros arcos de Invincible. Mark debe decidir qué valores son realmente suyos y no simplemente heredados de un padre que resultó ser diferente a lo que creía."},
  {t:"m",q:"¿Cómo aborda Invincible el tema del legado y la herencia en comparación con otros cómics de superhéroes?",o:["Examina críticamente si los valores heredados son realmente propios o simplemente adoptados por necesidad","Celebra sin cuestionamiento el legado de los padres superhéroes","Ignora el tema del legado para centrarse exclusivamente en la acción","Concluye que los hijos de superhéroes siempre son mejores que sus padres"],a:0,exp:"Invincible examina críticamente la herencia: Mark constantemente debe decidir qué tomar y qué rechazar del legado de Nolan, tanto sus poderes Viltrumitas como su crianza humana.",extra:"Esta exploración hace de Invincible algo más que un cómic de acción: es una narrativa sobre identidad, libre albedrío y la capacidad de elegir ser diferente a los patrones heredados."},
  {t:"m",q:"¿Qué villano de Invincible puede manipular dimensiones alternativas y usa ese poder para reunir un ejército de versiones alternativas de sí mismo?",o:["Angstrom Levy","El Reverso","Alternate Omniman","Multi-Paul"],a:0,exp:"Angstrom Levy usa su capacidad de viaje dimensional para reunir versiones alternativas de sí mismo de múltiples universos paralelos, absorbiendo su conocimiento combinado.",extra:"El proceso que usa para absorber conocimiento sale mal cuando Invincible interrumpe el ritual, desfigurando a Levy y causando que culpe a Mark de su condición."},
  {t:"m",q:"¿Qué aspectos de la primera temporada de la serie animada de Invincible fueron más elogiados por crítica y audiencia?",o:["La animación, las actuaciones de voz y la valentía narrativa para abordar temas oscuros sin censurarse","Los efectos de sonido exclusivos de la serie","La fidelidad absoluta al material fuente sin ningún cambio","La banda sonora orquestal que reemplaza el silencio del cómic"],a:0,exp:"La primera temporada fue elogiada por su animación fluida especialmente en escenas de acción, las actuaciones vocales y su disposición a no censurar los momentos más oscuros del cómic.",extra:"El clímax de la temporada 1 con la pelea Invincible-Omni-Man fue especialmente destacado por su intensidad emocional y su brutalidad bien ejecutada. Generó un enorme pico de popularidad para la serie."},
  {t:"m",q:"¿Cuál es el nombre de la editorial independiente cofundada por Todd McFarlane que publica Invincible?",o:["Image Comics","Dark Horse Comics","IDW Publishing","Oni Press"],a:0,exp:"Image Comics fue cofundada en 1992 por Todd McFarlane (Spawn), Jim Lee (X-Men), Rob Liefeld y otros artistas que querían retener los derechos de sus creaciones.",extra:"La política de Image de permitir que los creadores sean dueños de sus personajes revolutionó la industria. Sin Image Comics, proyectos como Invincible, Saga, The Walking Dead y muchos otros no existirían en la forma actual."},
  {t:"m",q:"¿Qué actor presta voz a Atom Eve en la serie animada de Amazon Prime Video?",o:["Gillian Jacobs","Zazie Beetz","Sandra Oh","Olivia Colman"],a:0,exp:"Gillian Jacobs, conocida por Community, interpreta a Atom Eve (Samantha Eve Wilkins) en la serie animada de Invincible.",extra:"Jacobs captura tanto la fortaleza como la vulnerabilidad del personaje. Atom Eve es uno de los personajes más complejos de la serie, equilibrando su inmenso poder con dilemas éticos profundos."},
  {t:"m",q:"¿Qué personaje secundario de Invincible es una heroína que puede reducir su tamaño a nivel microscópico?",o:["Shrinking Ray","Atom Eve en su forma comprimida","Micro-God","Pinpoint"],a:0,exp:"Shrinking Ray es una superheroína con capacidad de reducir su tamaño hasta escala microscópica, siendo miembro de los Guardianes del Globo.",extra:"Como muchos personajes de Invincible, Shrinking Ray existe en un universo donde los poderes son más variados y menos normalizados que en Marvel o DC, reflejando la multiplicidad de poderes posibles."},
  {t:"f",q:"En el cómic de Invincible, los personajes que mueren pueden volver a la vida si el guionista lo decide, como en los grandes cómics de Marvel y DC.",o:["Verdadero","Falso"],a:1,exp:"Una de las reglas fundamentales de Invincible es que la muerte es permanente para la mayoría de personajes. Robert Kirkman evitó deliberadamente el recurso de resurrecciones constantes del mainstream.",extra:"Esta regla hace que los momentos de peligro sean genuinamente tensos: el lector nunca puede estar seguro de que un personaje querido sobrevivirá. Es lo opuesto a la 'muerte de superhéroe' típica de Marvel/DC donde todos regresan."},
  {t:"f",q:"La serie animada de Invincible en Amazon Prime fue producida con un presupuesto notablemente bajo comparado con otras series de animación adulta de plataformas de streaming.",o:["Verdadero","Falso"],a:1,exp:"Invincible fue producida con un presupuesto considerable para Amazon, resultando en una animación de alta calidad especialmente en las secuencias de acción.",extra:"La inversión se nota en la fluidez de los combates y la expresividad de los personajes. Amazon apostó fuerte por la propiedad dado el éxito previo del cómic y la popularidad de Robert Kirkman tras The Walking Dead."},
  {t:"f",q:"Invincible es la única serie de superhéroes de Robert Kirkman publicada en Image Comics.",o:["Verdadero","Falso"],a:1,exp:"Kirkman publicó varias series en Image Comics además de Invincible, siendo The Walking Dead la más famosa. También escribió Marvel Zombies para Marvel Comics.",extra:"The Walking Dead (2003-2019) fue publicada simultáneamente con Invincible en Image Comics. Ambas son consideradas las obras más importantes de Kirkman en el cómic independiente."},
  {t:"m",q:"¿Cuál es el poder principal de Rex Splode y cómo lo usa en combate?",o:["Puede cargar objetos con energía cinética potencial que explota al impactar o al activarse","Puede generar explosiones desde su propio cuerpo sin objetos externos","Su poder es telepático: paraliza a los enemigos con miedo","Puede crear objetos físicos que luego hace explotar remotamente"],a:0,exp:"Rex Splode puede transferir energía cinética potencial a objetos al tocarlos, que luego explotan al activarse o al impactar. Necesita objetos físicos como proyectiles para usar su poder.",extra:"Este mecanismo limita a Rex respecto a personajes como Atom Eve o los Viltrumitas, pero también lo hace más creativo tácticamente: siempre lleva encima múltiples objetos pequeños para usar como munición."},
  {t:"f","q":"En la serie animada de Invincible, el papel de Amber Bennett fue expandido respecto al cómic original.",o:["Verdadero","Falso"],a:0,exp:"La serie animada expandió el papel de Amber Bennett, dándole más agencia y presencia narrativa de la que tenía en los cómics originales.",extra:"Este tipo de cambio es común en adaptaciones: personajes secundarios del cómic reciben más desarrollo en el formato televisivo para dar mayor profundidad a las relaciones del protagonista."},
  {t:"f",q:"El Gran Regente Thragg es derrotado fácilmente por Mark Grayson en su primer enfrentamiento directo.",o:["Verdadero","Falso"],a:1,exp:"Thragg es presentado como uno de los Viltrumitas más poderosos que existen. Sus enfrentamientos con Mark son brutales y Mark sufre graves consecuencias cada vez.",extra:"Thragg es el Gran Regente del Imperio Viltrumita y el antagonista principal de los arcos finales. Su derrota eventual requiere todo el crecimiento de Mark como guerrero durante toda la serie."},
  {t:"f",q:"Invincible recibió una adaptación de videojuego ampliamente elogiada con múltiples secuelas comerciales.",o:["Verdadero","Falso"],a:1,exp:"No existe una adaptación de videojuego de Invincible ampliamente conocida o elogiada. La propiedad ha tenido mayor éxito en cómic y serie animada.",extra:"Robert Kirkman ha expresado interés en adaptaciones de videojuego pero hasta la fecha no ha habido ningún lanzamiento destacado basado en la propiedad Invincible."},
  {t:"f",q:"Cecil Stedman es un personaje completamente heroico y transparente en sus métodos para proteger a la Tierra.",o:["Verdadero","Falso"],a:1,exp:"Cecil usa métodos extremadamente cuestionables: manipulación, secretos, experimentos no éticos y sacrificios de inocentes justificados por el bien mayor. Es una figura moralmente ambigua.",extra:"La relación entre Cecil y Mark representa el conflicto clásico entre el idealismo (Mark) y el pragmatismo oscuro (Cecil) en la narrativa de superhéroes."}
];

export default invincibleQuestions;
